      try {
        const res = await fetch(`/api/documentos?leadId=${lead.id}`);
        const json = await res.json();
        if (json.success && json.data) {
          setDocsSubidos(json.data.map((d: Record<string, any>) => ({
            ...d,
            creadoEn: d.creadoEn ? new Date(d.creadoEn) : new Date(),
          })));
        }
      } catch {
