export default function SolicitudesPage() {
  const router = useRouter();
  const { usuarioActual } = useUser();
  const [solicitudes, setSolicitudes] = useState<any[]>([]);
  const [cargando, setCargando] = useState(true);
  const [busqueda, setBusqueda] = useState("");
  const [filtroEstado, setFiltroEstado] = useState("todos");
  const [vistaActiva, setVistaActiva] = useState<"tabla" | "tarjetas">("tarjetas");

  useEffect(() => {
    async function cargar() {
      try {
        const res = await fetch("/api/solicitudes", { credentials: "include" });
        const data = await res.json();
        if (data.success) setSolicitudes(data.data || []);
      } catch (err) {
        console.error("Error cargando solicitudes:", err);
      } finally {
        setCargando(false);
      }
    }
    cargar();
  }, []);

  const solicitudesFiltradas = useMemo(() => {
    return solicitudes.filter((s) => {
      const matchBusqueda = !busqueda || 
        s.tipoCredito?.toLowerCase().includes(busqueda.toLowerCase()) ||
        s.bancoAsignado?.toLowerCase().includes(busqueda.toLowerCase());
      const matchEstado = filtroEstado === "todos" || s.estado === filtroEstado;
      return matchBusqueda && matchEstado;
    });
  }, [solicitudes, busqueda, filtroEstado]);

  const estadisticas = useMemo(() => {
    const total = solicitudes.length;
    const enProceso = solicitudes.filter(s => !["COMPLETADO", "RECHAZADO"].includes(s.estado)).length;
    const aprobados = solicitudes.filter(s => ["APROBADO", "DESEMBOLSADO", "COMPLETADO"].includes(s.estado)).length;
    const montoTotal = solicitudes.reduce((sum, s) => sum + (s.montoSolicitado || 0), 0);
    return { total, enProceso, aprobados, montoTotal };
  }, [solicitudes]);

  if (cargando) {
    return (
      <div className="flex items-center justify-center py-20">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Solicitudes</h1>
          <p className="text-sm text-slate-500">Gestión de expedientes hipotecarios</p>
        </div>
        <button className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-xl text-sm font-semibold hover:bg-blue-700 transition-colors">
          <Plus size={16} /> Nueva Solicitud
        </button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-white rounded-xl p-4 border border-slate-100 shadow-sm">
          <div className="text-sm text-slate-500">Total</div>
          <div className="text-2xl font-bold text-slate-900">{estadisticas.total}</div>
        </div>
        <div className="bg-white rounded-xl p-4 border border-slate-100 shadow-sm">
          <div className="text-sm text-slate-500">En Proceso</div>
          <div className="text-2xl font-bold text-blue-600">{estadisticas.enProceso}</div>
        </div>
        <div className="bg-white rounded-xl p-4 border border-slate-100 shadow-sm">
          <div className="text-sm text-slate-500">Aprobados</div>
          <div className="text-2xl font-bold text-emerald-600">{estadisticas.aprobados}</div>
        </div>
        <div className="bg-white rounded-xl p-4 border border-slate-100 shadow-sm">
          <div className="text-sm text-slate-500">Monto Total</div>
          <div className="text-2xl font-bold text-slate-900">{formatoMonedaAbreviado(estadisticas.montoTotal)}</div>
        </div>
      </div>

      {/* Filters */}
      <div className="flex items-center gap-3">
        <div className="flex-1 relative">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
          <input
            type="text"
            placeholder="Buscar por tipo de crédito o banco..."
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
          />
        </div>
        <select
          value={filtroEstado}
          onChange={(e) => setFiltroEstado(e.target.value)}
          className="px-4 py-2.5 bg-white border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20"
        >
          <option value="todos">Todos los estados</option>
          {Object.entries(ESTADOS_CONFIG).map(([key, config]) => (
            <option key={key} value={key}>{config.label}</option>
          ))}
        </select>
        <div className="flex bg-white border border-slate-200 rounded-xl overflow-hidden">
          <button
            onClick={() => setVistaActiva("tarjetas")}
            className={`p-2.5 ${vistaActiva === "tarjetas" ? "bg-blue-50 text-blue-600" : "text-slate-400 hover:bg-slate-50"}`}
          >
            <LayoutGrid size={16} />
          </button>
          <button
            onClick={() => setVistaActiva("tabla")}
            className={`p-2.5 ${vistaActiva === "tabla" ? "bg-blue-50 text-blue-600" : "text-slate-400 hover:bg-slate-50"}`}
          >
            <List size={16} />
          </button>
        </div>
      </div>

      {/* Lista de solicitudes */}
      {solicitudesFiltradas.length === 0 ? (
        <div className="text-center py-16 bg-white rounded-xl border border-slate-100">
          <FileText size={48} className="text-slate-200 mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-slate-600 mb-2">No hay solicitudes</h3>
          <p className="text-sm text-slate-400">Crea una nueva solicitud para comenzar</p>
        </div>
      ) : vistaActiva === "tarjetas" ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {solicitudesFiltradas.map((solicitud) => {
            const config = ESTADOS_CONFIG[solicitud.estado] || ESTADOS_CONFIG.EN_REVISION;
            return (
              <div
                key={solicitud.id}
                onClick={() => router.push(`/solicitudes/${solicitud.id}`)}
                className="bg-white rounded-xl border border-slate-100 p-4 cursor-pointer hover:shadow-md transition-shadow"
              >
                <div className="flex items-start justify-between mb-3">
                  <span className={`text-[10px] font-bold px-2 py-1 rounded-full ${config.bgColor}`}>
                    {config.label}
                  </span>
                  <span className="text-[10px] text-slate-400">{solicitud.creadoEn?.split("T")[0]}</span>
                </div>
                <h3 className="font-semibold text-slate-800 mb-1">{solicitud.tipoCredito}</h3>
                <div className="flex items-center gap-4 text-[11px] text-slate-500">
                  <span className="flex items-center gap-1">
                    <DollarSign size={12} /> {formatoMonedaAbreviado(solicitud.montoSolicitado)}
                  </span>
                  {solicitud.bancoAsignado && (
                    <span className="flex items-center gap-1">
                      <Building2 size={12} /> {solicitud.bancoAsignado}
                    </span>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="bg-white rounded-xl border border-slate-100 overflow-hidden">
          <table className="w-full">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
                <th className="text-left px-4 py-3 text-[10px] font-bold text-slate-400 uppercase">Tipo</th>
                <th className="text-left px-4 py-3 text-[10px] font-bold text-slate-400 uppercase">Monto</th>
                <th className="text-left px-4 py-3 text-[10px] font-bold text-slate-400 uppercase">Banco</th>
                <th className="text-left px-4 py-3 text-[10px] font-bold text-slate-400 uppercase">Estado</th>
                <th className="text-left px-4 py-3 text-[10px] font-bold text-slate-400 uppercase">Fecha</th>
                <th className="text-right px-4 py-3 text-[10px] font-bold text-slate-400 uppercase">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {solicitudesFiltradas.map((solicitud) => {
                const config = ESTADOS_CONFIG[solicitud.estado] || ESTADOS_CONFIG.EN_REVISION;
                return (
                  <tr
                    key={solicitud.id}
                    onClick={() => router.push(`/solicitudes/${solicitud.id}`)}
                    className="hover:bg-blue-50/20 cursor-pointer"
                  >
                    <td className="px-4 py-3 text-sm font-medium text-slate-800">{solicitud.tipoCredito}</td>
                    <td className="px-4 py-3 text-sm text-slate-600">{formatoMonedaAbreviado(solicitud.montoSolicitado)}</td>
                    <td className="px-4 py-3 text-sm text-slate-600">{solicitud.bancoAsignado || "-"}</td>
                    <td className="px-4 py-3">
                      <span className={`text-[10px] font-bold px-2 py-1 rounded-full ${config.bgColor}`}>
                        {config.label}
                      </span>
                    </td>
                    <td className="px-4 py-3 text-sm text-slate-500">{solicitud.creadoEn?.split("T")[0]}</td>
                    <td className="px-4 py-3 text-right">
                      <button className="p-1.5 hover:bg-slate-100 rounded-lg">
                        <Eye size={14} className="text-slate-400" />
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

"use client";

import { use, useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import {
  ArrowLeft,
  Clock,
  Play,
  CheckCircle,
  AlertTriangle,
  Calendar,
  User,
  FileText,
  Tag,
  Send,
  History,
  MessageSquare,
  Timer,
  Trash2,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { ConfirmDialog } from "@/components/ui/confirm-dialog";
import { ESTADOS_TAREA_CONFIG, TIPOS_TAREA_CONFIG } from "@/tipos";
import type { Tarea, EstadoTarea } from "@/tipos";

const prioridadStyles: Record<string, { label: string; class: string }> = {
  BAJA: { label: "Baja", class: "bg-slate-100 text-slate-600" },
  MEDIA: { label: "Media", class: "bg-blue-50 text-blue-600 border border-blue-100" },
  ALTA: { label: "Alta", class: "bg-orange-50 text-orange-600 border border-orange-100" },
  URGENTE: { label: "Urgente", class: "bg-red-50 text-red-600 border border-red-100" },
};

const estadoIcono: Record<EstadoTarea, React.ReactNode> = {
  PENDIENTE: <Clock size={14} className="text-amber-500" />,
  EN_PROGRESO: <Play size={14} className="text-blue-500" />,
  COMPLETADA: <CheckCircle size={14} className="text-emerald-500" />,
  VENCIDA: <AlertTriangle size={14} className="text-red-500" />,
};

export default function TareaDetallePage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = use(params);
  const router = useRouter();
  const [tarea, setTarea] = useState<Tarea | null>(null);
  const [cargando, setCargando] = useState(true);
  const [nuevoComentario, setNuevoComentario] = useState("");
  const [eliminarOpen, setEliminarOpen] = useState(false);

  useEffect(() => {
    async function cargarTarea() {
      try {
        const res = await fetch(`/api/tareas/${id}`);
        const json = await res.json();
        if (json.success && json.data) {
          setTarea({
            ...json.data,
            fechaVencimiento: json.data.fechaVencimiento ? new Date(json.data.fechaVencimiento) : undefined,
            creadoEn: json.data.creadoEn ? new Date(json.data.creadoEn) : new Date(),
            comentarios: json.data.comentarios || [],
            historial: json.data.historial || [],
            etiquetas: json.data.etiquetas ? (typeof json.data.etiquetas === "string" ? json.data.etiquetas.split(",") : json.data.etiquetas) : [],
          });
        }
      } catch {
        setTarea(null);
      } finally {
        setCargando(false);
      }
    }
    cargarTarea();
  }, [id]);

  if (cargando) {
    return (
      <div className="flex items-center justify-center py-20">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
        <span className="ml-3 text-sm text-slate-500">Cargando tarea...</span>
      </div>
    );
  }

  if (!tarea) {
    return (
      <div className="flex flex-col items-center justify-center py-20">
        <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center mb-4">
          <FileText size={24} className="text-slate-300" />
        </div>
        <h2 className="text-sm font-bold text-slate-600 mb-1">
          Tarea no encontrada
        </h2>
        <p className="text-[11px] text-slate-400 mb-4">
          La tarea que buscas no existe o fue eliminada.
        </p>
        <Button onClick={() => router.push("/tareas")} size="sm">
          Volver a Tareas
        </Button>
      </div>
    );
  }

  const cambiarEstado = async (nuevoEstado: EstadoTarea) => {
    if (!tarea) return;
    try {
      await fetch(`/api/tareas/${tarea.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ estado: nuevoEstado }),
      });
      setTarea((prev) => prev ? { ...prev, estado: nuevoEstado } : prev);
    } catch {
      // Error silencioso
    }
  };

  const agregarComentario = async () => {
    if (!nuevoComentario.trim() || !tarea) return;
    const comentario = {
      id: `c-${Date.now()}`,
      autor: "Usuario Actual",
      contenido: nuevoComentario.trim(),
      creadoEn: new Date(),
    };
    try {
      await fetch(`/api/tareas/${tarea.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          comentarios: [...(tarea.comentarios || []), comentario],
        }),
      });
      setTarea((prev) => prev ? {
        ...prev,
        comentarios: [...(prev.comentarios || []), comentario],
      } : prev);
      setNuevoComentario("");
    } catch {
      // Error silencioso
    }
  };

  const handleEliminar = async () => {
    if (!tarea) return;
    try {
      await fetch(`/api/tareas/${tarea.id}`, { method: "DELETE" });
      router.push("/tareas");
    } catch {
      // Error silencioso
    }
  };

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <button
            onClick={() => router.push("/tareas")}
            className="p-2 hover:bg-slate-100 rounded-lg transition-colors"
          >
            <ArrowLeft size={18} className="text-slate-600" />
          </button>
          <div>
            <h1 className="text-base font-bold text-slate-900">
              {tarea.titulo}
            </h1>
            <div className="flex items-center gap-2 mt-0.5">
              <span
                className="text-[9px] font-bold px-2 py-0.5 rounded-md"
                style={{
                  backgroundColor: `${ESTADOS_TAREA_CONFIG[tarea.estado].color}15`,
                  color: ESTADOS_TAREA_CONFIG[tarea.estado].color,
                }}
              >
                {ESTADOS_TAREA_CONFIG[tarea.estado].label}
              </span>
              <span
                className={`text-[9px] font-bold px-2 py-0.5 rounded-md ${prioridadStyles[tarea.prioridad].class}`}
              >
                {prioridadStyles[tarea.prioridad].label}
              </span>
              <span
                className="text-[9px] font-semibold px-2 py-0.5 rounded-md"
                style={{
                  backgroundColor: `${TIPOS_TAREA_CONFIG[tarea.tipo].color}15`,
                  color: TIPOS_TAREA_CONFIG[tarea.tipo].color,
                }}
              >
                {TIPOS_TAREA_CONFIG[tarea.tipo].label}
              </span>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-2">
          {tarea.estado !== "COMPLETADA" && (
            <Button
              variant="outline"
              size="sm"
              onClick={() => cambiarEstado("COMPLETADA")}
              className="gap-1.5 text-emerald-600 border-emerald-200 hover:bg-emerald-50"
            >
              <CheckCircle size={13} /> Completar
            </Button>
          )}
          {tarea.estado === "COMPLETADA" && (
            <Button
              variant="outline"
              size="sm"
              onClick={() => cambiarEstado("PENDIENTE")}
              className="gap-1.5"
            >
              <Play size={13} /> Reabrir
            </Button>
          )}
          <Button
            variant="outline"
            size="sm"
            onClick={() => setEliminarOpen(true)}
            className="gap-1.5 text-red-500 border-red-200 hover:bg-red-50"
          >
            <Trash2 size={13} /> Eliminar
          </Button>
        </div>
      </div>

      {/* Contenido */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-5">
        {/* Columna izquierda - Info */}
        <div className="lg:col-span-2 space-y-4">
          {/* Lead asociado */}
          {tarea.leadNombre && (
            <div className="bg-white rounded-2xl border border-slate-100/80 p-4 shadow-soft">
              <h3 className="text-xs font-bold text-slate-800 mb-3 flex items-center gap-1.5">
                <User size={13} className="text-blue-500" />
                Lead Asociado
              </h3>
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl flex items-center justify-center text-white text-[11px] font-bold">
                  {tarea.leadNombre
                    .split(" ")
                    .map((n) => n[0])
                    .join("")}
                </div>
                <div>
                  <div className="text-[12px] font-bold text-slate-800">
                    {tarea.leadNombre}
                  </div>
                  <button
                    onClick={() =>
                      router.push(`/clientes/${tarea.leadId}`)
                    }
                    className="text-[10px] text-blue-500 hover:underline"
                  >
                    Ver perfil completo
                  </button>
                </div>
              </div>
            </div>
          )}

          {/* Descripción */}
          {tarea.descripcion && (
            <div className="bg-white rounded-2xl border border-slate-100/80 p-4 shadow-soft">
              <h3 className="text-xs font-bold text-slate-800 mb-2 flex items-center gap-1.5">
                <FileText size={13} className="text-slate-400" />
                Descripción
              </h3>
              <p className="text-[11px] text-slate-600 leading-relaxed">
                {tarea.descripcion}
              </p>
            </div>
          )}

          {/* Comentarios */}
          <div className="bg-white rounded-2xl border border-slate-100/80 p-4 shadow-soft">
            <h3 className="text-xs font-bold text-slate-800 mb-3 flex items-center gap-1.5">
              <MessageSquare size={13} className="text-purple-500" />
              Comentarios ({tarea.comentarios.length})
            </h3>
            <div className="space-y-3 mb-4">
              {tarea.comentarios.length === 0 ? (
                <p className="text-[11px] text-slate-400 text-center py-4">
                  Sin comentarios aún
                </p>
              ) : (
                tarea.comentarios.map((c) => (
                  <div key={c.id} className="flex gap-3">
                    <div className="w-7 h-7 bg-gradient-to-br from-slate-400 to-slate-500 rounded-lg flex items-center justify-center text-[8px] font-bold text-white flex-shrink-0 mt-0.5">
                      {c.autor
                        .split(" ")
                        .map((n) => n[0])
                        .join("")}
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-0.5">
                        <span className="text-[10px] font-bold text-slate-700">
                          {c.autor}
                        </span>
                        <span className="text-[9px] text-slate-400">
                          {new Date(c.creadoEn).toLocaleDateString("es-CL")}
                        </span>
                      </div>
                      <p className="text-[11px] text-slate-600">
                        {c.contenido}
                      </p>
                    </div>
                  </div>
                ))
              )}
            </div>
            {/* Input comentario */}
            <div className="flex gap-2">
              <input
                type="text"
                value={nuevoComentario}
                onChange={(e) => setNuevoComentario(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && agregarComentario()}
                placeholder="Escribe un comentario..."
                className="flex-1 px-3 py-2 bg-slate-50 border border-slate-200/60 rounded-xl text-[11px] text-slate-600 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500/10 focus:border-blue-400"
              />
              <Button
                size="sm"
                onClick={agregarComentario}
                disabled={!nuevoComentario.trim()}
              >
                <Send size={13} />
              </Button>
            </div>
          </div>
        </div>

        {/* Columna derecha - Detalles + Historial */}
        <div className="space-y-4">
          {/* Detalles */}
          <div className="bg-white rounded-2xl border border-slate-100/80 p-4 shadow-soft">
            <h3 className="text-xs font-bold text-slate-800 mb-3">
              Detalles
            </h3>
            <div className="space-y-3">
              <DetalleRow
                icon={<User size={12} className="text-slate-400" />}
                label="Asignado a"
                value={
                  tarea.nombreEjecutivo || "Sin asignar"
                }
              />
              <DetalleRow
                icon={<Calendar size={12} className="text-slate-400" />}
                label="Vencimiento"
                value={
                  tarea.fechaVencimiento
                    ? new Date(tarea.fechaVencimiento).toLocaleDateString(
                        "es-CL"
                      )
                    : "Sin fecha"
                }
                highlighted={
                  tarea.fechaVencimiento &&
                  new Date(tarea.fechaVencimiento) < new Date() &&
                  tarea.estado !== "COMPLETADA"
                }
              />
              <DetalleRow
                icon={<Timer size={12} className="text-slate-400" />}
                label="Duración estimada"
                value={
                  tarea.duracionEstimada
                    ? `${tarea.duracionEstimada} min`
                    : "No definida"
                }
              />
              <DetalleRow
                icon={<Calendar size={12} className="text-slate-400" />}
                label="Creado"
                value={new Date(tarea.creadoEn).toLocaleDateString("es-CL")}
              />
              {tarea.recordatorio && (
                <DetalleRow
                  icon={<Clock size={12} className="text-amber-400" />}
                  label="Recordatorio"
                  value={new Date(tarea.recordatorio).toLocaleString("es-CL")}
                />
              )}
              {tarea.etiquetas && tarea.etiquetas.length > 0 && (
                <div className="flex items-start gap-2">
                  <Tag size={12} className="text-slate-400 mt-0.5" />
                  <div className="flex flex-wrap gap-1">
                    {tarea.etiquetas.map((et) => (
                      <span
                        key={et}
                        className="text-[9px] font-semibold px-2 py-0.5 rounded-full bg-slate-100 text-slate-600"
                      >
                        {et}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Historial */}
          <div className="bg-white rounded-2xl border border-slate-100/80 p-4 shadow-soft">
            <h3 className="text-xs font-bold text-slate-800 mb-3 flex items-center gap-1.5">
              <History size={13} className="text-indigo-500" />
              Historial
            </h3>
            <div className="space-y-3">
              {tarea.historial.length === 0 ? (
                <p className="text-[11px] text-slate-400 text-center py-4">
                  Sin historial
                </p>
              ) : (
                [...tarea.historial]
                  .reverse()
                  .map((h, idx) => (
                    <div key={h.id} className="flex gap-3">
                      <div className="flex flex-col items-center">
                        <div
                          className={`w-2 h-2 rounded-full ${
                            idx === 0 ? "bg-blue-500" : "bg-slate-300"
                          }`}
                        />
                        {idx < tarea.historial.length - 1 && (
                          <div className="w-px flex-1 bg-slate-200 mt-1" />
                        )}
                      </div>
                      <div className="pb-3">
                        <p className="text-[10px] font-semibold text-slate-700">
                          {h.accion}
                        </p>
                        <p className="text-[9px] text-slate-400">
                          {h.usuario} •{" "}
                          {new Date(h.fecha).toLocaleDateString("es-CL")}
                        </p>
                        {h.detalle && (
                          <p className="text-[9px] text-slate-500 mt-0.5 italic">
                            {h.detalle}
                          </p>
                        )}
                      </div>
                    </div>
                  ))
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Dialog Eliminar */}
      <ConfirmDialog
        open={eliminarOpen}
        onOpenChange={setEliminarOpen}
        title="Eliminar Tarea"
        description={`¿Eliminar "${tarea.titulo}"? Esta acción no se puede deshacer.`}
        confirmLabel="Eliminar"
        variant="danger"
        onConfirm={handleEliminar}
      />
    </div>
  );
}

function DetalleRow({
  icon,
  label,
  value,
  highlighted,
}: {
  icon: React.ReactNode;
  label: string;
  value: string;
  highlighted?: boolean;
}) {
  return (
    <div className="flex items-center gap-2">
      {icon}
      <div className="flex-1">
        <span className="text-[9px] text-slate-400">{label}</span>
        <div
          className={`text-[11px] font-medium ${
            highlighted ? "text-red-500" : "text-slate-700"
          }`}
        >
          {value}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useMemo, useEffect } from "react";
import { Search, Plus, Zap } from "lucide-react";
import { StatsBar, KPIGrid } from "@/componentes/triggers/StatsBar";
import { TriggerCard } from "@/componentes/triggers/TriggerCard";
import { useTriggers, useTriggerHistorial } from "@/modulos/automatizacion/hooks";
import { TRIGGERS_TIPOS, ACCIONES_TIPOS, CONDICION_OPERADORES, TRIGGER_CATEGORIAS, CAMPOS_POR_CATEGORIA } from "@/modulos/automatizacion/config";
import { toast } from "sonner";

type TabTrigger = "todos" | "activos" | "pausados" | "borrador";

export default function TriggersPage() {
  const { triggers, setTriggers, cargando } = useTriggers();
  const [tabActiva, setTabActiva] = useState<TabTrigger>("todos");
  const [busqueda, setBusqueda] = useState("");
  const [modalCrear, setModalCrear] = useState(false);
  const [modalDetalle, setModalDetalle] = useState<string | null>(null);
  const [triggerEditando, setTriggerEditando] = useState<any>(null);

  const triggersFiltrados = useMemo(() => {
    return triggers.filter((t) => {
      const coincideTab =
        tabActiva === "todos" ||
        (tabActiva === "activos" && t.estado === "ACTIVO") ||
        (tabActiva === "pausados" && t.estado === "PAUSADO") ||
        (tabActiva === "borrador" && t.estado === "BORRADOR");
      const coincideBusqueda =
        !busqueda ||
        t.nombre?.toLowerCase().includes(busqueda.toLowerCase()) ||
        t.descripcion?.toLowerCase().includes(busqueda.toLowerCase());
      return coincideTab && coincideBusqueda;
    });
  }, [tabActiva, busqueda, triggers]);

  const stats = useMemo(() => ({
    total: triggers.length,
    activos: triggers.filter((t) => t.estado === "ACTIVO").length,
    pausados: triggers.filter((t) => t.estado === "PAUSADO").length,
    borrador: triggers.filter((t) => t.estado === "BORRADOR").length,
    ejecuciones: triggers.reduce((sum, t) => sum + (t.ejecuciones || 0), 0),
    exitosas: triggers.reduce((sum, t) => sum + (t.exitosas || 0), 0),
    fallidas: triggers.reduce((sum, t) => sum + (t.fallidas || 0), 0),
  }), [triggers]);

  const tasaExito = stats.ejecuciones > 0 ? Math.round((stats.exitosas / stats.ejecuciones) * 100) : 0;

  const toggleEstado = async (triggerId: string) => {
    const trigger = triggers.find((t) => t.id === triggerId);
    if (!trigger) return;
    const nuevoEstado = trigger.estado === "ACTIVO" ? "PAUSADO" : "ACTIVO";
    try {
      const res = await fetch(`/api/triggers/${triggerId}`, {
        method: "PUT", credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ estado: nuevoEstado }),
      });
      if (res.ok) {
        setTriggers((prev) => prev.map((t) => t.id === triggerId ? { ...t, estado: nuevoEstado } : t));
        toast.success(`Trigger ${nuevoEstado === "ACTIVO" ? "activado" : "pausado"}`);
      }
    } catch { toast.error("Error al cambiar estado"); }
  };

  const eliminarTrigger = async (triggerId: string) => {
    if (!confirm("Ã‚Â¿EstÃƒÂ¡s seguro de eliminar este trigger?")) return;
    try {
      const res = await fetch(`/api/triggers/${triggerId}`, { method: "DELETE", credentials: "include" });
      if (res.ok) {
        setTriggers((prev) => prev.filter((t) => t.id !== triggerId));
        toast.success("Trigger eliminado");
      }
    } catch { toast.error("Error al eliminar"); }
  };

  const abrirEditor = (trigger?: any) => {
    setTriggerEditando(trigger || null);
    setModalCrear(true);
  };

  const guardarTrigger = async (data: any) => {
    try {
      const url = triggerEditando ? `/api/triggers/${triggerEditando.id}` : "/api/triggers";
      const method = triggerEditando ? "PUT" : "POST";
      const res = await fetch(url, {
        method, credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });
      if (res.ok) {
        const json = await res.json();
        if (triggerEditando) {
          setTriggers((prev) => prev.map((t) => t.id === triggerEditando.id ? { ...t, ...data } : t));
          toast.success("Trigger actualizado");
        } else {
          setTriggers((prev) => [json.data || { ...data, id: crypto.randomUUID() }, ...prev]);
          toast.success("Trigger creado");
        }
        setModalCrear(false);
        setTriggerEditando(null);
      }
    } catch { toast.error("Error al guardar"); }
  };

  return (
    <div className="space-y-5">
      <StatsBar total={stats.total} activos={stats.activos} ejecuciones={stats.ejecuciones} tasaExito={tasaExito} />
      <KPIGrid stats={stats} />
      <div className="bg-white rounded-2xl border border-slate-100/80 p-4 shadow-soft">
        <div className="flex items-center justify-between">
          <div className="flex gap-1.5">
            {[
              { id: "todos", label: "Todos", count: stats.total },
              { id: "activos", label: "Activos", count: stats.activos },
              { id: "pausados", label: "Pausados", count: stats.pausados },
              { id: "borrador", label: "Borrador", count: stats.borrador },
            ].map((tab) => (
              <button key={tab.id} onClick={() => setTabActiva(tab.id as TabTrigger)}
                className={`flex items-center gap-1.5 px-4 py-2 rounded-xl text-[11px] font-semibold transition-all ${
                  tabActiva === tab.id ? "bg-amber-500 text-white shadow-md shadow-amber-500/20" : "bg-slate-50 text-slate-500 hover:bg-slate-100"
                }`}>
                {tab.label}
                <span className={`text-[11px] px-1.5 py-0.5 rounded-full ${tabActiva === tab.id ? "bg-white/20" : "bg-slate-200"}`}>{tab.count}</span>
              </button>
            ))}
          </div>
          <div className="flex items-center gap-3">
            <div className="relative">
              <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
              <input type="text" placeholder="Buscar trigger..." value={busqueda} onChange={(e) => setBusqueda(e.target.value)}
                className="w-48 pl-9 pr-3 py-2 bg-slate-50 border border-slate-200/60 rounded-xl text-[11px] text-slate-600 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-amber-500/10 focus:border-amber-400 transition-all" />
            </div>
            <button onClick={() => abrirEditor()}
              className="flex items-center gap-1.5 px-4 py-2 bg-amber-500 text-white rounded-xl text-[11px] font-semibold hover:bg-amber-600 transition-colors shadow-md shadow-amber-500/20">
              <Plus size={14} /> Nuevo Trigger
            </button>
          </div>
        </div>
      </div>
      {cargando ? (
        <div className="space-y-4">
          {[1, 2, 3].map((i) => (
            <div key={i} className="bg-white rounded-2xl border border-slate-100/80 p-5 shadow-soft animate-pulse">
              <div className="flex items-start gap-4"><div className="w-12 h-12 bg-slate-200 rounded-xl" /><div className="flex-1 space-y-2"><div className="h-4 bg-slate-200 rounded w-1/3" /><div className="h-3 bg-slate-200 rounded w-2/3" /></div></div>
            </div>
          ))}
        </div>
      ) : triggersFiltrados.length === 0 ? (
        <div className="bg-white rounded-2xl border border-slate-100/80 p-12 shadow-soft text-center">
          <Zap size={48} className="mx-auto text-slate-300 mb-4" />
          <h3 className="text-sm font-bold text-slate-600 mb-2">No hay triggers</h3>
          <p className="text-[11px] text-slate-400 mb-4">{busqueda ? "No se encontraron triggers" : "Crea tu primer trigger para automatizar tareas"}</p>
          {!busqueda && <button onClick={() => abrirEditor()} className="px-4 py-2 bg-amber-500 text-white rounded-xl text-[11px] font-semibold hover:bg-amber-600 transition-colors"><Plus size={14} className="inline mr-1" /> Crear Trigger</button>}
        </div>
      ) : (
        <div className="space-y-4">
          {triggersFiltrados.map((trigger) => (
            <TriggerCard key={trigger.id} trigger={trigger} onToggleEstado={toggleEstado} onVerDetalle={setModalDetalle} onEditar={abrirEditor} onEliminar={eliminarTrigger} />
          ))}
        </div>
      )}
      {modalCrear && <TriggerEditorModal trigger={triggerEditando} onGuardar={guardarTrigger} onCerrar={() => { setModalCrear(false); setTriggerEditando(null); }} />}
      {modalDetalle && <TriggerDetalleModal triggerId={modalDetalle} onCerrar={() => setModalDetalle(null)} onEditar={(t) => { setModalDetalle(null); abrirEditor(t); }} />}
    </div>
  );
}
// --- Modal Editor de Trigger ---
function TriggerEditorModal({ trigger, onGuardar, onCerrar }: { trigger: any; onGuardar: (data: any) => void; onCerrar: () => void }) {
  const [paso, setPaso] = useState(1);
  const [form, setForm] = useState({
    nombre: trigger?.nombre || "", descripcion: trigger?.descripcion || "",
    trigger: trigger?.trigger || TRIGGERS_TIPOS[0].id, categoria: trigger?.categoria || "lead",
    condiciones: trigger?.condiciones || [], logica_condiciones: trigger?.logica_condiciones || "AND",
    acciones: trigger?.acciones || [], estado: trigger?.estado || "BORRADOR",
  });
  const camposDisponibles = CAMPOS_POR_CATEGORIA[form.categoria] || [];
  const agregarCondicion = () => setForm((p) => ({ ...p, condiciones: [...p.condiciones, { campo: camposDisponibles[0]?.id || "", operador: "igual", valor: "" }] }));
  const eliminarCondicion = (idx: number) => setForm((p) => ({ ...p, condiciones: p.condiciones.filter((_: any, i: number) => i !== idx) }));
  const actualizarCondicion = (idx: number, campo: string, valor: any) => setForm((p) => ({ ...p, condiciones: p.condiciones.map((c: any, i: number) => i === idx ? { ...c, [campo]: valor } : c) }));
  const agregarAccion = (tipo: string) => setForm((p) => ({ ...p, acciones: [...p.acciones, { tipo, configuracion: {}, delay: 0, orden: p.acciones.length + 1 }] }));
  const eliminarAccion = (idx: number) => setForm((p) => ({ ...p, acciones: p.acciones.filter((_: any, i: number) => i !== idx).map((a: any, i: number) => ({ ...a, orden: i + 1 })) }));
  const handleSubmit = () => { if (!form.nombre || !form.trigger || form.acciones.length === 0) { toast.error("Completa todos los campos obligatorios"); return; } onGuardar(form); };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl w-full max-w-2xl mx-4 shadow-2xl overflow-hidden max-h-[90vh] overflow-y-auto">
        <div className="p-6 border-b border-slate-100">
          <div className="flex items-center justify-between">
            <div><h3 className="text-base font-bold text-slate-800">{trigger ? "Editar Trigger" : "Nuevo Trigger"}</h3>
            <p className="text-[11px] text-slate-400 mt-0.5">Paso {paso} de 3: {paso === 1 ? "Configuracion" : paso === 2 ? "Condiciones" : "Acciones"}</p></div>
            <button onClick={onCerrar} className="p-2 hover:bg-slate-100 rounded-lg transition-colors"><span className="text-slate-400">?</span></button>
          </div>
          <div className="flex gap-2 mt-4">{[1, 2, 3].map((p) => <div key={p} className={`h-1 flex-1 rounded-full transition-colors ${p <= paso ? "bg-amber-500" : "bg-slate-200"}`} />)}</div>
        </div>
        <div className="p-6">
          {paso === 1 && (
            <div className="space-y-5">
              <div className="space-y-1.5"><label className="text-[11px] font-semibold text-slate-700">Nombre del Trigger *</label>
                <input type="text" placeholder="Ej: Bienvenida Nuevo Lead" value={form.nombre} onChange={(e) => setForm((p) => ({ ...p, nombre: e.target.value }))}
                  className="w-full h-10 px-3 bg-white border border-slate-200/60 rounded-xl text-[12px] text-slate-600 focus:outline-none focus:ring-2 focus:ring-amber-500/10 focus:border-amber-400 transition-all" /></div>
              <div className="space-y-1.5"><label className="text-[11px] font-semibold text-slate-700">Descripcion</label>
                <textarea placeholder="Describe que hace este trigger..." rows={2} value={form.descripcion} onChange={(e) => setForm((p) => ({ ...p, descripcion: e.target.value }))}
                  className="w-full px-3 py-2 bg-white border border-slate-200/60 rounded-xl text-[12px] text-slate-600 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-amber-500/10 focus:border-amber-400 resize-none transition-all" /></div>
              <div className="space-y-1.5"><label className="text-[11px] font-semibold text-slate-700">Evento Trigger *</label>
                <select value={form.trigger} onChange={(e) => { const val = e.target.value; const cat = TRIGGERS_TIPOS.find((t) => t.id === val)?.categoria || "lead"; setForm((p) => ({ ...p, trigger: val, categoria: cat })); }}
                  className="w-full h-10 px-3 bg-white border border-slate-200/60 rounded-xl text-[12px] text-slate-600 focus:outline-none focus:ring-2 focus:ring-amber-500/10 focus:border-amber-400">
