          setUsuario({
            ...json.data,
            ultimoAcceso: json.data.ultimoAcceso ? new Date(json.data.ultimoAcceso) : undefined,
            creadoEn: json.data.creadoEn ? new Date(json.data.creadoEn) : new Date(),
