      prioridad: "MEDIA",
      situacionlaboral: sitLaboral,
      tipocredito: tipoCredito,
      rentamensual: rentaMensual,
      complementarrenta: complementarRenta === "Sí" || complementarRenta === "si",
      endicom: enDicom === "Sí" || enDicom === "si",
      dicomdetalle: dicomDetalle,
