"use client";

import { useState, useMemo, useRef, useEffect } from "react";
import {
  Phone,
  Video,
  MoreHorizontal,
  Search,
  Info,
  X,
  Hash,
  MessageSquare,
  Reply,
} from "lucide-react";
import { toast } from "sonner";
import { Avatar } from "./Avatar";
import { MensajeItem } from "./MensajeItem";
import { InputMensaje } from "./InputMensaje";
import { useChat } from "@/lib/hooks/useChat";
import { useUser } from "@/lib/contexts/UserContext";
import type { Mensaje, Conversacion } from "@/tipos/conversaciones";

interface AreaChatProps {
  conversacionId: string | null;
  usuarioActualId: string;
}

export function AreaChat({ conversacionId, usuarioActualId }: AreaChatProps) {
  const { usuarios, usuarioActual } = useUser();
  const [conversacion, setConversacion] = useState<Conversacion | null>(null);
  const [mostrarInfo, setMostrarInfo] = useState(false);
  const [busquedaChat, setBusquedaChat] = useState("");
  const [respondiendoA, setRespondiendoA] = useState<Mensaje | null>(null);
  const mensajesRef = useRef<HTMLDivElement>(null);

  const { mensajes, cargando, enviando, enviarMensaje, eliminarMensaje, reaccionarMensaje } = useChat({
    conversacionId,
    usuarioActualId,
    usuarioActualNombre: `${usuarioActual.nombre} ${usuarioActual.apellido}`,
  });

  // Cargar datos de la conversación
  useEffect(() => {
    if (!conversacionId) {
      setConversacion(null);
      return;
    }

    async function cargarConversacion() {
      try {
        const res = await fetch(`/api/conversaciones/${conversacionId}`);
        const json = await res.json();
        if (json.success && json.data) {
          setConversacion({
            id: json.data.id,
            nombre: json.data.nombre,
            tipo: json.data.tipo,
            participantes: json.data.participantes || [],
            mensajesNoLeidos: json.data.mensajesNoLeidos || 0,
            descripcion: json.data.descripcion,
            esFijo: json.data.esFijo,
            creadoEn: new Date(json.data.creadoEn || Date.now()),
            creadoPor: json.data.creadoPor || "",
          });
        }
      } catch {
        setConversacion(null);
      }
    }

    cargarConversacion();
  }, [conversacionId]);

  useEffect(() => {
    // Scroll al fondo cuando cambian los mensajes
    const timer = setTimeout(() => {
      if (mensajesRef.current) {
        mensajesRef.current.scrollTop = mensajesRef.current.scrollHeight;
      }
    }, 100);
    return () => clearTimeout(timer);
  }, [mensajes.length, conversacionId]);

  const mensajesAgrupados = useMemo(() => {
    if (!mensajes || mensajes.length === 0) return [];
    return mensajes.map((msg, idx) => {
      const prev = idx > 0 ? mensajes[idx - 1] : null;
      const mostrarRemitente =
        !prev ||
        prev.remitenteId !== msg.remitenteId ||
        (msg.creadoEn && prev.creadoEn && msg.creadoEn.getTime() - prev.creadoEn.getTime() > 300000);

      const primerDelDia =
        !prev ||
        (msg.creadoEn && prev.creadoEn && msg.creadoEn.toDateString() !== prev.creadoEn.toDateString());

      return { ...msg, mostrarRemitente, primerDelDia };
    });
  }, [mensajes]);

  const handleEnviarMensaje = (contenido: string) => {
    const texto = respondiendoA
      ? `> ${respondiendoA.remitenteNombre}: ${respondiendoA.contenido.split("\n")[0]}\n\n${contenido}`
      : contenido;
    enviarMensaje(texto);
    setRespondiendoA(null);
  };

  const handleEliminarMensaje = async (mensajeId: string) => {
    await eliminarMensaje(mensajeId);
    toast.success("Mensaje eliminado");
  };

  const handleReaccionar = async (mensajeId: string, emoji: string) => {
    await reaccionarMensaje(mensajeId, emoji);
  };

  const getNombreConversacion = (): string => {
    if (!conversacion) return "";
    if (conversacion.tipo === "DIRECTO") {
      const otroId = conversacion.participantes.find((p) => p !== usuarioActualId);
      if (!otroId) return conversacion.nombre;
      const otro = usuarios.find((u) => u.id === otroId);
      return otro ? `${otro.nombre} ${otro.apellido}` : conversacion.nombre;
    }
    return conversacion.nombre;
  };

  const getDescripcionConversacion = (): string => {
    if (!conversacion) return "";
    if (conversacion.descripcion) return conversacion.descripcion;
    return `${conversacion.participantes.length} participantes`;
  };

  const mensajesFiltrados = useMemo(() => {
    if (!busquedaChat.trim()) return mensajesAgrupados;
    const q = busquedaChat.toLowerCase();
    return mensajesAgrupados.filter((m) => m.contenido?.toLowerCase().includes(q));
  }, [mensajesAgrupados, busquedaChat]);

  const getOtroUsuario = () => {
    if (!conversacion || conversacion.tipo !== "DIRECTO") return null;
    const otroId = conversacion.participantes.find((p) => p !== usuarioActualId);
    return otroId ? usuarios.find((u) => u.id === otroId) : null;
  };

  if (!conversacionId || !conversacion) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center bg-gradient-to-br from-slate-50 to-slate-100">
        <div className="text-center">
          <div className="w-20 h-20 bg-white rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg border border-slate-100">
            <MessageSquare size={32} className="text-slate-400" />
          </div>
          <h3 className="text-lg font-bold text-slate-700 mb-2">Selecciona una conversación</h3>
          <p className="text-sm text-slate-500 max-w-xs">
            Elige una conversación de la lista para empezar a chatear con tu equipo.
          </p>
        </div>
      </div>
    );
  }

  const nombreConversacion = getNombreConversacion();
  const descripcionConversacion = getDescripcionConversacion();
  const esDirecto = conversacion.tipo === "DIRECTO";
  const otroId = esDirecto ? conversacion.participantes.find((p) => p !== usuarioActualId) : null;

  return (
    <div className="flex-1 flex flex-col bg-white h-full">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-slate-200 bg-white flex-shrink-0">
        <div className="flex items-center gap-3">
          {esDirecto && otroId ? (
            <Avatar nombre={nombreConversacion} id={otroId} size="md" />
          ) : (
            <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl flex items-center justify-center text-white shadow-sm">
              <Hash size={18} />
            </div>
          )}
          <div>
            <div className="flex items-center gap-2">
              <h3 className="text-sm font-bold text-slate-900">{nombreConversacion}</h3>
              {conversacion.esFijo && (
                <span className="text-amber-500 text-xs">📌</span>
              )}
            </div>
            <p className="text-[11px] text-slate-500">{descripcionConversacion}</p>
          </div>
        </div>

        <div className="flex items-center gap-1">
          <button
            onClick={() => setBusquedaChat(busquedaChat ? "" : " ")}
            className={`p-2 rounded-lg transition-colors ${busquedaChat ? "bg-blue-100 text-blue-600" : "hover:bg-slate-100 text-slate-500"}`}
            title="Buscar en conversación"
          >
            <Search size={16} />
          </button>
          <button
            onClick={() => {
              const otro = getOtroUsuario();
              if (otro?.telefono) window.open(`tel:${otro.telefono}`, "_self");
              else toast.info("Sin número de teléfono");
            }}
            className="p-2 hover:bg-slate-100 rounded-lg transition-colors text-slate-500"
            title="Llamar"
          >
            <Phone size={16} />
          </button>
          <button
            onClick={() => toast.info("Videollamada próximamente")}
            className="p-2 hover:bg-slate-100 rounded-lg transition-colors text-slate-500"
            title="Videollamada"
          >
            <Video size={16} />
          </button>
          <button
            onClick={() => setMostrarInfo(!mostrarInfo)}
            className={`p-2 rounded-lg transition-colors ${
              mostrarInfo ? "bg-blue-100 text-blue-600" : "hover:bg-slate-100 text-slate-500"
            }`}
            title="Información"
          >
            <Info size={16} />
          </button>
          <button
            onClick={() => toast.info("Opciones de conversación próximamente")}
            className="p-2 hover:bg-slate-100 rounded-lg transition-colors text-slate-500"
            title="Más opciones"
          >
            <MoreHorizontal size={16} />
          </button>
        </div>
      </div>

      {/* Barra de búsqueda */}
      {busquedaChat && (
        <div className="px-4 py-2 border-b border-slate-100 bg-slate-50 flex items-center gap-2">
          <Search size={14} className="text-slate-400" />
          <input
            autoFocus
            type="text"
            value={busquedaChat === " " ? "" : busquedaChat}
            onChange={(e) => setBusquedaChat(e.target.value || " ")}
            placeholder="Buscar mensajes..."
            className="flex-1 bg-transparent text-xs text-slate-600 placeholder:text-slate-400 focus:outline-none"
          />
          <span className="text-[10px] text-slate-400">{mensajesFiltrados.length} resultados</span>
          <button onClick={() => setBusquedaChat("")} className="p-0.5 hover:bg-slate-200 rounded">
            <X size={12} className="text-slate-400" />
          </button>
        </div>
      )}

      {/* Content */}
      <div className="flex-1 flex overflow-hidden">
        {/* Mensajes */}
        <div className="flex-1 flex flex-col">
          <div ref={mensajesRef} className="flex-1 overflow-y-auto py-4">
            {cargando ? (
              <div className="flex items-center justify-center h-full">
                <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-600"></div>
                <span className="ml-2 text-xs text-slate-500">Cargando mensajes...</span>
              </div>
            ) : mensajesFiltrados.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-center p-4">
                <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center mb-4">
                  <Hash size={24} className="text-slate-400" />
                </div>
                <h4 className="text-sm font-semibold text-slate-600 mb-1">
                  Inicio de la conversación
                </h4>
                <p className="text-xs text-slate-400 max-w-xs">
                  Este es el comienzo de tu conversación en #{nombreConversacion}.
                  ¡Envía el primer mensaje!
                </p>
              </div>
            ) : (
              mensajesFiltrados.map((msg) => (
                <MensajeItem
                  key={msg.id}
                  mensaje={msg}
                  esPropio={msg.remitenteId === usuarioActualId}
                  mostrarRemitente={msg.mostrarRemitente}
                  esPrimerDelDia={msg.primerDelDia}
                  onEliminar={handleEliminarMensaje}
                  onReaccionar={handleReaccionar}
                  onResponder={(m) => setRespondiendoA(m)}
                />
              ))
            )}
          </div>

          {/* Barra de respuesta */}
          {respondiendoA && (
            <div className="px-4 py-2 bg-blue-50 border-t border-blue-100 flex items-center justify-between">
              <div className="flex items-center gap-2 min-w-0">
                <Reply size={14} className="text-blue-500 flex-shrink-0" />
                <div className="min-w-0">
                  <span className="text-[10px] font-bold text-blue-700">{respondiendoA.remitenteNombre}</span>
                  <p className="text-[10px] text-blue-500 truncate">{respondiendoA.contenido}</p>
                </div>
              </div>
              <button onClick={() => setRespondiendoA(null)} className="p-1 hover:bg-blue-100 rounded">
                <X size={12} className="text-blue-400" />
              </button>
            </div>
          )}

          <InputMensaje
            onEnviar={handleEnviarMensaje}
            nombreConversacion={nombreConversacion}
            disabled={enviando}
          />
        </div>

        {/* Panel de información */}
        {mostrarInfo && (
          <div className="w-72 border-l border-slate-200 bg-slate-50/50 flex flex-col overflow-y-auto">
            <div className="p-4 border-b border-slate-200 flex items-center justify-between">
              <h4 className="text-xs font-bold text-slate-700 uppercase tracking-wider">
                Información
              </h4>
              <button
                onClick={() => setMostrarInfo(false)}
                className="p-1 hover:bg-slate-200 rounded-md transition-colors"
              >
                <X size={14} className="text-slate-500" />
              </button>
            </div>

            <div className="p-4 border-b border-slate-200 text-center">
              {esDirecto && otroId ? (
                <Avatar nombre={nombreConversacion} id={otroId} size="lg" />
              ) : (
                <div className="w-16 h-16 bg-gradient-to-br from-blue-500 to-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto">
                  <Hash size={24} />
                </div>
              )}
              <h3 className="text-sm font-bold text-slate-900 mt-3">{nombreConversacion}</h3>
              <p className="text-[11px] text-slate-500 mt-1">{descripcionConversacion}</p>
            </div>

            <div className="p-4">
              <h5 className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-3">
                Participantes ({conversacion.participantes.length})
              </h5>
              <div className="space-y-2">
                {conversacion.participantes.map((pid) => {
                  const usuario = usuarios.find((u) => u.id === pid);
                  if (!usuario) return null;

                  return (
                    <div key={pid} className="flex items-center gap-2.5">
                      <Avatar
                        nombre={`${usuario.nombre} ${usuario.apellido}`}
                        id={pid}
                        size="sm"
                      />
                      <div className="flex-1 min-w-0">
                        <div className="text-xs font-semibold text-slate-700 truncate">
                          {usuario.nombre} {usuario.apellido}
                        </div>
                      </div>
                      <span className="text-[9px] text-slate-400 bg-slate-100 px-1.5 py-0.5 rounded">
                        {usuario.rol?.replace("_", " ")}
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import {
  Send,
  Paperclip,
  Smile,
  AtSign,
  Image,
  Mic,
  Bold,
  Italic,
  Code,
  Link,
  List,
  X,
} from "lucide-react";
import { toast } from "sonner";

const EMOJIS_COMUNES = ["👍", "❤️", "😊", "😂", "🎉", "🔥", "👏", "💪", "✅", "⭐", "🙏", "💡"];

interface InputMensajeProps {
  onEnviar: (contenido: string) => void;
  nombreConversacion: string;
  disabled?: boolean;
}

export function InputMensaje({ onEnviar, nombreConversacion, disabled }: InputMensajeProps) {
  const [mensaje, setMensaje] = useState("");
  const [mostrarFormato, setMostrarFormato] = useState(false);
  const [mostrarEmojis, setMostrarEmojis] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 120)}px`;
    }
  }, [mensaje]);

  const handleEnviar = () => {
    if (!mensaje.trim()) return;
    onEnviar(mensaje.trim());
    setMensaje("");
    setMostrarEmojis(false);
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleEnviar();
    }
  };

  const insertarFormato = (prefix: string, suffix: string) => {
    const textarea = textareaRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const textoSeleccionado = mensaje.substring(start, end);

    const nuevoMensaje =
      mensaje.substring(0, start) +
      prefix +
      (textoSeleccionado || "texto") +
      suffix +
      mensaje.substring(end);

    setMensaje(nuevoMensaje);

    setTimeout(() => {
      textarea.focus();
      const newStart = start + prefix.length;
      const newEnd = textoSeleccionado
        ? newStart + textoSeleccionado.length
        : newStart + 4;
      textarea.setSelectionRange(newStart, newEnd);
    }, 0);
  };

  const insertarEmoji = (emoji: string) => {
    const textarea = textareaRef.current;
    if (!textarea) return;
    const start = textarea.selectionStart;
    const nuevo = mensaje.substring(0, start) + emoji + mensaje.substring(start);
    setMensaje(nuevo);
    setTimeout(() => {
      textarea.focus();
      textarea.setSelectionRange(start + emoji.length, start + emoji.length);
    }, 0);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>, tipo: string) => {
    const archivo = e.target.files?.[0];
    if (!archivo) return;
    const tamanho = (archivo.size / 1024).toFixed(1);
    setMensaje((prev) => prev + `[${tipo}: ${archivo.name} (${tamanho} KB)]`);
    e.target.value = "";
  };

  return (
    <div className="border-t border-slate-200 bg-white">
      {/* Barra de formato */}
      {mostrarFormato && (
        <div className="flex items-center gap-1 px-4 py-2 border-b border-slate-100">
          <button
            onClick={() => insertarFormato("**", "**")}
            className="p-1.5 hover:bg-slate-100 rounded-md transition-colors"
            title="Negrita"
          >
            <Bold size={14} className="text-slate-500" />
          </button>
          <button
            onClick={() => insertarFormato("_", "_")}
            className="p-1.5 hover:bg-slate-100 rounded-md transition-colors"
            title="Cursiva"
          >
            <Italic size={14} className="text-slate-500" />
          </button>
          <button
            onClick={() => insertarFormato("`", "`")}
            className="p-1.5 hover:bg-slate-100 rounded-md transition-colors"
            title="Código"
          >
            <Code size={14} className="text-slate-500" />
          </button>
          <button
            onClick={() => insertarFormato("[", "](url)")}
            className="p-1.5 hover:bg-slate-100 rounded-md transition-colors"
            title="Enlace"
          >
            <Link size={14} className="text-slate-500" />
          </button>
          <button
            onClick={() => insertarFormato("\n• ", "")}
            className="p-1.5 hover:bg-slate-100 rounded-md transition-colors"
            title="Lista"
          >
            <List size={14} className="text-slate-500" />
          </button>
          <div className="w-px h-4 bg-slate-200 mx-1" />
          <button
            onClick={() => setMostrarFormato(false)}
            className="p-1.5 hover:bg-slate-100 rounded-md transition-colors"
          >
            <X size={14} className="text-slate-400" />
          </button>
        </div>
      )}

      {/* Panel de emojis */}
      {mostrarEmojis && (
        <div className="px-4 py-2 border-b border-slate-100 bg-slate-50">
          <div className="flex items-center gap-1 flex-wrap">
            {EMOJIS_COMUNES.map((emoji) => (
              <button
                key={emoji}
                onClick={() => insertarEmoji(emoji)}
                className="w-8 h-8 text-lg hover:bg-slate-200 rounded-lg transition-colors flex items-center justify-center"
              >
                {emoji}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Input area */}
      <div className="p-4">
        <div className="flex items-end gap-2 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 focus-within:border-blue-400 focus-within:ring-2 focus-within:ring-blue-500/10 transition-all">
          {/* Botones izquierda */}
          <div className="flex items-center gap-1 pb-0.5">
            <button
              onClick={() => setMostrarFormato(!mostrarFormato)}
              className={`p-1.5 rounded-lg transition-colors ${
                mostrarFormato ? "bg-blue-100 text-blue-600" : "hover:bg-slate-200 text-slate-500"
              }`}
              title="Formato"
            >
              <Bold size={16} />
            </button>
            <button
              onClick={() => fileInputRef.current?.click()}
              className="p-1.5 hover:bg-slate-200 rounded-lg transition-colors text-slate-500"
              title="Adjuntar archivo"
            >
              <Paperclip size={16} />
            </button>
            <button
              onClick={() => imageInputRef.current?.click()}
              className="p-1.5 hover:bg-slate-200 rounded-lg transition-colors text-slate-500"
              title="Enviar imagen"
            >
              <Image size={16} />
            </button>
            <input ref={fileInputRef} type="file" className="hidden" onChange={(e) => handleFileSelect(e, "Archivo")} />
            <input ref={imageInputRef} type="file" accept="image/*" className="hidden" onChange={(e) => handleFileSelect(e, "Imagen")} />
          </div>

          {/* Textarea */}
          <textarea
            ref={textareaRef}
            value={mensaje}
            onChange={(e) => setMensaje(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder={disabled ? "Enviando mensaje..." : `Escribe un mensaje en ${nombreConversacion}...`}
            rows={1}
            disabled={disabled}
            className="flex-1 bg-transparent text-sm text-slate-700 placeholder:text-slate-400 focus:outline-none resize-none py-1 max-h-[120px] disabled:opacity-50"
          />

          {/* Botones derecha */}
          <div className="flex items-center gap-1 pb-0.5">
            <button
              onClick={() => { insertarFormato("@", " "); setMostrarEmojis(false); }}
              className="p-1.5 hover:bg-slate-200 rounded-lg transition-colors text-slate-500"
              title="Mencionar"
            >
              <AtSign size={16} />
            </button>
            <button
              onClick={() => { setMostrarEmojis(!mostrarEmojis); setMostrarFormato(false); }}
              className={`p-1.5 rounded-lg transition-colors ${mostrarEmojis ? "bg-blue-100 text-blue-600" : "hover:bg-slate-200 text-slate-500"}`}
              title="Emojis"
            >
              <Smile size={16} />
            </button>
            <button
              onClick={() => toast.info("Grabación de voz próximamente")}
              className="p-1.5 hover:bg-slate-200 rounded-lg transition-colors text-slate-500"
              title="Mensaje de voz"
            >
              <Mic size={16} />
            </button>
            <div className="w-px h-4 bg-slate-200 mx-1" />
            <button
              onClick={handleEnviar}
              disabled={!mensaje.trim() || disabled}
              className={`p-2 rounded-xl transition-all ${
                mensaje.trim() && !disabled
                  ? "bg-blue-500 text-white hover:bg-blue-600 shadow-lg shadow-blue-500/25"
                  : "bg-slate-200 text-slate-400 cursor-not-allowed"
              }`}
              title="Enviar mensaje"
            >
              {disabled ? (
                <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
              ) : (
                <Send size={16} />
              )}
            </button>
          </div>
        </div>

        {/* Hint */}
        <div className="flex items-center justify-between mt-2 px-1">
          <p className="text-[10px] text-slate-400">
            <kbd className="px-1 py-0.5 bg-slate-100 border border-slate-200 rounded text-[9px] font-mono">Enter</kbd> enviar ·{" "}
            <kbd className="px-1 py-0.5 bg-slate-100 border border-slate-200 rounded text-[9px] font-mono">Shift+Enter</kbd> nueva línea
          </p>
          {mensaje.length > 0 && (
            <p className="text-[10px] text-slate-400">{mensaje.length} caracteres</p>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import {
  Search,
  Hash,
  Users,
  MessageSquare,
  Plus,
  ChevronDown,
  ChevronRight,
  Bell,
  X,
  Check,
} from "lucide-react";
import { Avatar } from "./Avatar";
import { useConversaciones } from "@/lib/hooks/useConversaciones";
import { useUser } from "@/lib/contexts/UserContext";
import type { Conversacion, TipoConversacion } from "@/tipos/conversaciones";
import { toast } from "sonner";

interface ListaConversacionesProps {
  conversacionActiva: string | null;
  onSeleccionarConversacion: (id: string) => void;
  usuarioActualId: string;
}

const TIPO_ICON: Record<TipoConversacion, typeof Hash> = {
  CANAL: Hash,
  GRUPO: Users,
  DIRECTO: MessageSquare,
};

const TIPO_LABEL: Record<TipoConversacion, string> = {
  CANAL: "Canales",
  GRUPO: "Grupos",
  DIRECTO: "Mensajes Directos",
};

export function ListaConversaciones({
  conversacionActiva,
  onSeleccionarConversacion,
  usuarioActualId,
}: ListaConversacionesProps) {
  const { usuarios } = useUser();
  const { conversaciones, cargando, crearConversacion, recargar } = useConversaciones({ usuarioActualId });
  const [busqueda, setBusqueda] = useState("");
  const [seccionesAbiertas, setSeccionesAbiertas] = useState<Record<TipoConversacion, boolean>>({
    CANAL: true,
    GRUPO: true,
    DIRECTO: true,
  });
  const [mostrarNuevaConversacion, setMostrarNuevaConversacion] = useState(false);
  const [nuevaConversacionNombre, setNuevaConversacionNombre] = useState("");
  const [nuevaConversacionTipo, setNuevaConversacionTipo] = useState<TipoConversacion>("DIRECTO");
  const [nuevaConversacionParticipantes, setNuevaConversacionParticipantes] = useState<string[]>([]);
  const [nuevaConversacionDescripcion, setNuevaConversacionDescripcion] = useState("");

  const toggleSeccion = (tipo: TipoConversacion) => {
    setSeccionesAbiertas((prev) => ({ ...prev, [tipo]: !prev[tipo] }));
  };

  const conversacionesFiltradas = useMemo(() => {
    const filtradas = conversaciones.filter((c) => {
      const participa = c.participantes?.includes(usuarioActualId);
      const coincideBusqueda =
        !busqueda ||
        c.nombre.toLowerCase().includes(busqueda.toLowerCase()) ||
        c.descripcion?.toLowerCase().includes(busqueda.toLowerCase());
      return participa && coincideBusqueda;
    });

    const agrupadas: Record<TipoConversacion, Conversacion[]> = {
      CANAL: [],
      GRUPO: [],
      DIRECTO: [],
    };

    filtradas.forEach((c) => {
      agrupadas[c.tipo as TipoConversacion]?.push(c);
    });

    Object.keys(agrupadas).forEach((tipo) => {
      agrupadas[tipo as TipoConversacion].sort((a, b) => {
        if (a.mensajesNoLeidos > 0 && b.mensajesNoLeidos === 0) return -1;
        if (a.mensajesNoLeidos === 0 && b.mensajesNoLeidos > 0) return 1;
        return 0;
      });
    });

    return agrupadas;
  }, [conversaciones, busqueda, usuarioActualId]);

  const getNombreParticipante = (conversacion: Conversacion): string => {
    if (conversacion.tipo !== "DIRECTO") return conversacion.nombre;
    const otroId = conversacion.participantes?.find((p) => p !== usuarioActualId);
    if (!otroId) return conversacion.nombre;
    const otro = usuarios.find((u) => u.id === otroId);
    return otro ? `${otro.nombre} ${otro.apellido}` : conversacion.nombre;
  };

  const totalNoLeidos = conversaciones
    .filter((c) => c.participantes?.includes(usuarioActualId))
    .reduce((acc, c) => acc + (c.mensajesNoLeidos || 0), 0);

  const handleCrearConversacion = async () => {
    if (!nuevaConversacionNombre.trim()) {
      toast.error("Ingresa un nombre para la conversación");
      return;
    }

    const participantes = nuevaConversacionTipo === "DIRECTO" 
      ? [usuarioActualId, ...nuevaConversacionParticipantes]
      : [usuarioActualId];

    const resultado = await crearConversacion({
      nombre: nuevaConversacionNombre,
      tipo: nuevaConversacionTipo,
      participantes,
      descripcion: nuevaConversacionDescripcion,
    });

    if (resultado) {
      toast.success("Conversación creada", { description: nuevaConversacionNombre });
      setMostrarNuevaConversacion(false);
      setNuevaConversacionNombre("");
      setNuevaConversacionParticipantes([]);
      setNuevaConversacionDescripcion("");
      onSeleccionarConversacion(resultado.id);
    } else {
      toast.error("Error al crear conversación");
    }
  };

  const toggleParticipante = (usuarioId: string) => {
    setNuevaConversacionParticipantes((prev) => {
      if (prev.includes(usuarioId)) {
        return prev.filter((id) => id !== usuarioId);
      }
      return [...prev, usuarioId];
    });
  };

  if (cargando) {
    return (
      <div className="w-80 bg-white border-r border-slate-200 flex flex-col h-full items-center justify-center">
        <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-600"></div>
        <span className="ml-2 text-xs text-slate-500">Cargando...</span>
      </div>
    );
  }

  return (
    <div className="w-80 bg-white border-r border-slate-200 flex flex-col h-full">
      {/* Header */}
      <div className="p-4 border-b border-slate-100">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            <h2 className="text-base font-bold text-slate-900">Mensajes</h2>
            {totalNoLeidos > 0 && (
              <span className="px-2 py-0.5 bg-blue-500 text-white text-[10px] font-bold rounded-full">
                {totalNoLeidos}
              </span>
            )}
          </div>
          <div className="flex items-center gap-1">
            <button className="p-1.5 hover:bg-slate-100 rounded-lg transition-colors" title="Notificaciones">
              <Bell size={16} className="text-slate-500" />
            </button>
            <button 
              onClick={() => setMostrarNuevaConversacion(true)}
              className="p-1.5 hover:bg-slate-100 rounded-lg transition-colors" 
              title="Nueva conversación"
            >
              <Plus size={16} className="text-slate-500" />
            </button>
          </div>
        </div>

        <div className="relative">
          <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
          <input
            type="text"
            placeholder="Buscar conversaciones..."
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
            className="w-full pl-9 pr-3 py-2 bg-slate-50 border border-slate-200/60 rounded-xl text-xs text-slate-600 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-400 transition-all"
          />
        </div>
      </div>

      {/* Lista */}
      <div className="flex-1 overflow-y-auto">
        {(["CANAL", "GRUPO", "DIRECTO"] as TipoConversacion[]).map((tipo) => {
          const items = conversacionesFiltradas[tipo];
