            <div>
              <div className="text-[9px] text-slate-400 uppercase font-medium">Tipo</div>
              <div className="text-[11px] font-semibold text-slate-700">{configTipo?.label}</div>
            </div>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

