              </div>

              {/* Condiciones */}
              <div>
                <h4 className="text-[11px] font-bold text-slate-600 mb-2">Condiciones</h4>
                {(!flujo.condiciones || flujo.condiciones.length === 0) ? (
                  <p className="text-[10px] text-slate-400 italic">Se ejecuta siempre</p>
                ) : (
                  <div className="space-y-1">
                    {flujo.condiciones.map((cond: any, idx: number) => (
                      <div key={idx} className="flex items-center gap-2 p-2 bg-slate-50 rounded-lg text-[11px]">
                        <span className="font-semibold text-slate-600">{cond.campo}</span>
                        <span className="text-slate-400">{cond.operador}</span>
                        <span className="font-bold text-slate-800">{cond.valor}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Acciones */}
              <div>
                <h4 className="text-[11px] font-bold text-slate-600 mb-2">Acciones</h4>
                <div className="space-y-1">
                  {(flujo.acciones || flujo.pasos || []).map((accion: any, idx: number) => {
                    const config = ACCIONES_TIPOS.find((a) => a.id === accion.tipo);
                    return (
                      <div key={idx} className="flex items-center gap-3 p-2 bg-slate-50 rounded-lg">
                        <span className="text-[10px] font-bold text-slate-400 w-5">{idx + 1}</span>
                        <span className="text-[11px] font-semibold text-slate-700">{config?.label || accion.tipo}</span>
                        {accion.delay > 0 && (
                          <span className="text-[10px] text-slate-400">
                            +{accion.delay >= 60 ? `${Math.round(accion.delay / 60)}h` : `${accion.delay}m`}
                          </span>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          ) : (
            <FlujoHistorial flujoId={flujoId} />
          )}
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-slate-100 flex items-center justify-end gap-2">
          <button
            onClick={onCerrar}
            className="px-4 py-2 text-[11px] font-semibold text-slate-600 hover:bg-slate-100 rounded-xl transition-colors"
          >
            Cerrar
          </button>
          <button
            onClick={() => onEditar(flujo)}
            className="px-4 py-2 bg-violet-500 text-white text-[11px] font-semibold rounded-xl hover:bg-violet-600 transition-colors flex items-center gap-1.5"
          >
            Editar
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { X, Plus, GripVertical, Zap } from "lucide-react";
import { TRIGGERS_TIPOS, TRIGGER_CATEGORIAS, CONDICION_OPERADORES, CAMPOS_POR_CATEGORIA, ACCIONES_TIPOS } from "@/modulos/automatizacion/config";
import { PasoFlujo } from "./PasoFlujo";
import { SelectorAccion } from "./SelectorAccion";
import { ConfigAccion } from "./ConfigAccion";
import { toast } from "sonner";

interface FlujoEditorPanelProps {
  flujo: any | null;
  onGuardar: (data: any) => void;
  onCerrar: () => void;
}

export function FlujoEditorPanel({ flujo, onGuardar, onCerrar }: FlujoEditorPanelProps) {
  const [form, setForm] = useState({
    nombre: flujo?.nombre || "",
    descripcion: flujo?.descripcion || "",
    trigger: flujo?.trigger || TRIGGERS_TIPOS[0].id,
    categoria: flujo?.categoria || "lead",
    condiciones: flujo?.condiciones || [],
    logica_condiciones: flujo?.logica_condiciones || "AND",
    acciones: flujo?.acciones || flujo?.pasos || [],
    estado: flujo?.estado || "BORRADOR",
  });

  const [mostrarSelectorAccion, setMostrarSelectorAccion] = useState(false);

  const camposDisponibles = CAMPOS_POR_CATEGORIA[form.categoria] || [];

  // Condiciones
  const agregarCondicion = () => {
    setForm((p) => ({
      ...p,
      condiciones: [...p.condiciones, { campo: camposDisponibles[0]?.id || "", operador: "igual", valor: "" }],
    }));
  };

  const eliminarCondicion = (idx: number) => {
    setForm((p) => ({
      ...p,
      condiciones: p.condiciones.filter((_: any, i: number) => i !== idx),
    }));
  };

  const actualizarCondicion = (idx: number, campo: string, valor: any) => {
    setForm((p) => ({
      ...p,
      condiciones: p.condiciones.map((c: any, i: number) => i === idx ? { ...c, [campo]: valor } : c),
    }));
  };

  // Acciones
  const agregarAccion = (tipo: string) => {
    setForm((p) => ({
      ...p,
      acciones: [...p.acciones, { tipo, configuracion: {}, delay: 0, orden: p.acciones.length + 1 }],
    }));
  };

  const eliminarAccion = (idx: number) => {
    setForm((p) => ({
      ...p,
      acciones: p.acciones.filter((_: any, i: number) => i !== idx).map((a: any, i: number) => ({ ...a, orden: i + 1 })),
    }));
  };

  const actualizarAccion = (idx: number, campo: string, valor: any) => {
    setForm((p) => ({
      ...p,
      acciones: p.acciones.map((a: any, i: number) => {
        if (i !== idx) return a;
        if (campo === "configuracion") return { ...a, configuracion: valor };
        return { ...a, [campo]: valor };
      }),
    }));
  };

  // Mover accion (drag-and-drop simplificado)
  const moverAccion = (idx: number, direccion: "arriba" | "abajo") => {
    const nuevoIdx = direccion === "arriba" ? idx - 1 : idx + 1;
    if (nuevoIdx < 0 || nuevoIdx >= form.acciones.length) return;

    const nuevasAcciones = [...form.acciones];
    const temp = nuevasAcciones[idx];
    nuevasAcciones[idx] = nuevasAcciones[nuevoIdx];
    nuevasAcciones[nuevoIdx] = temp;

    // Actualizar orden
    nuevasAcciones.forEach((a: any, i: number) => a.orden = i + 1);
    setForm((p) => ({ ...p, acciones: nuevasAcciones }));
  };

  const handleSubmit = () => {
    if (!form.nombre || !form.trigger || form.acciones.length === 0) {
      toast.error("Completa todos los campos obligatorios");
      return;
    }
    onGuardar(form);
  };

  return (
    <>
      <div className="fixed inset-0 z-40 bg-black/30 backdrop-blur-sm" onClick={onCerrar} />
      <div className="fixed top-0 right-0 bottom-0 w-full max-w-md bg-white shadow-2xl z-50 flex flex-col">
        {/* Header */}
        <div className="p-4 border-b border-slate-100 flex items-center justify-between">
          <div>
            <h3 className="text-sm font-bold text-slate-800">
              {flujo ? "Editar Flujo" : "Nuevo Flujo"}
            </h3>
            <p className="text-[10px] text-slate-400 mt-0.5">Configura tu flujo de automatizacion</p>
          </div>
          <button onClick={onCerrar} className="p-2 hover:bg-slate-100 rounded-lg transition-colors">
            <X size={16} className="text-slate-400" />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-4 space-y-5">
          {/* Nombre */}
          <div className="space-y-1.5">
            <label className="text-[11px] font-semibold text-slate-700">Nombre *</label>
            <input
              type="text"
              placeholder="Ej: Bienvenida Nuevo Lead"
              value={form.nombre}
              onChange={(e) => setForm((p) => ({ ...p, nombre: e.target.value }))}
              className="w-full h-10 px-3 bg-white border border-slate-200/60 rounded-xl text-[12px] text-slate-600 focus:outline-none focus:ring-2 focus:ring-violet-500/10 focus:border-violet-400 transition-all"
            />
          </div>

          {/* Descripcion */}
          <div className="space-y-1.5">
            <label className="text-[11px] font-semibold text-slate-700">Descripcion</label>
            <textarea
              placeholder="Describe que hace este flujo..."
              rows={2}
              value={form.descripcion}
              onChange={(e) => setForm((p) => ({ ...p, descripcion: e.target.value }))}
              className="w-full px-3 py-2 bg-white border border-slate-200/60 rounded-xl text-[12px] text-slate-600 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-violet-500/10 focus:border-violet-400 resize-none transition-all"
            />
          </div>

          {/* Trigger */}
          <div className="space-y-1.5">
            <label className="text-[11px] font-semibold text-slate-700">Evento Trigger *</label>
            <select
              value={form.trigger}
              onChange={(e) => {
                const val = e.target.value;
                const cat = TRIGGERS_TIPOS.find((t) => t.id === val)?.categoria || "lead";
                setForm((p) => ({ ...p, trigger: val, categoria: cat }));
              }}
              className="w-full h-10 px-3 bg-white border border-slate-200/60 rounded-xl text-[12px] text-slate-600 focus:outline-none focus:ring-2 focus:ring-violet-500/10 focus:border-violet-400"
            >
              {TRIGGER_CATEGORIAS.map((cat) => (
                <optgroup key={cat.id} label={cat.label}>
                  {TRIGGERS_TIPOS.filter((t) => t.categoria === cat.id).map((tipo) => (
                    <option key={tipo.id} value={tipo.id}>{tipo.label}</option>
                  ))}
                </optgroup>
              ))}
            </select>
          </div>

          {/* Condiciones */}
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <label className="text-[11px] font-semibold text-slate-700">Condiciones</label>
              <div className="flex gap-1">
                {(["AND", "OR"] as const).map((logica) => (
                  <button
                    key={logica}
                    onClick={() => setForm((p) => ({ ...p, logica_condiciones: logica }))}
                    className={`px-2 py-1 rounded-lg text-[9px] font-semibold transition-all ${
                      form.logica_condiciones === logica
                        ? "bg-violet-500 text-white"
                        : "bg-slate-100 text-slate-500 hover:bg-slate-200"
                    }`}
                  >
                    {logica}
                  </button>
                ))}
              </div>
            </div>

            {form.condiciones.length === 0 ? (
              <div className="p-3 bg-slate-50 rounded-xl border border-dashed border-slate-300 text-center">
                <p className="text-[10px] text-slate-400">Sin condiciones = se ejecuta siempre</p>
              </div>
            ) : (
              <div className="space-y-2">
                {form.condiciones.map((cond: any, idx: number) => (
                  <div key={idx} className="flex items-center gap-2 p-2 bg-slate-50 rounded-xl">
                    <select
                      value={cond.campo}
                      onChange={(e) => actualizarCondicion(idx, "campo", e.target.value)}
                      className="h-8 px-2 bg-white border border-slate-200 rounded-lg text-[10px] text-slate-600 flex-1"
                    >
                      {camposDisponibles.map((campo) => (
                        <option key={campo.id} value={campo.id}>{campo.label}</option>
                      ))}
                    </select>
                    <select
                      value={cond.operador}
                      onChange={(e) => actualizarCondicion(idx, "operador", e.target.value)}
                      className="h-8 px-2 bg-white border border-slate-200 rounded-lg text-[10px] text-slate-600"
                    >
                      {CONDICION_OPERADORES.map((op) => (
                        <option key={op.id} value={op.id}>{op.label}</option>
                      ))}
                    </select>
                    {!["esta_vacio", "no_vacio"].includes(cond.operador) && (
                      <input
                        type="text"
                        placeholder="Valor"
                        value={cond.valor || ""}
                        onChange={(e) => actualizarCondicion(idx, "valor", e.target.value)}
                        className="h-8 px-2 bg-white border border-slate-200 rounded-lg text-[10px] text-slate-600 flex-1"
                      />
                    )}
                    <button
                      onClick={() => eliminarCondicion(idx)}
                      className="p-1 text-red-400 hover:text-red-600 hover:bg-red-50 rounded"
                    >
                      <X size={12} />
                    </button>
                  </div>
                ))}
              </div>
            )}
            <button
              onClick={agregarCondicion}
              className="text-[10px] font-semibold text-violet-600 hover:text-violet-700"
            >
              + Agregar condicion
            </button>
          </div>

          {/* Acciones */}
          <div className="space-y-2">
            <label className="text-[11px] font-semibold text-slate-700">Acciones *</label>

            {form.acciones.length === 0 ? (
              <div className="p-4 bg-slate-50 rounded-xl border border-dashed border-slate-300 text-center">
                <p className="text-[10px] text-slate-400">Agrega al menos una accion</p>
              </div>
            ) : (
              <div className="space-y-2">
                {form.acciones.map((accion: any, idx: number) => (
                  <ConfigAccion
                    key={idx}
                    accion={accion}
                    index={idx}
                    onActualizar={actualizarAccion}
                  />
                ))}
              </div>
            )}

            <button
              onClick={() => setMostrarSelectorAccion(true)}
              className="w-full flex items-center justify-center gap-2 p-2 bg-violet-50 hover:bg-violet-100 rounded-xl border border-dashed border-violet-300 transition-all"
            >
              <Plus size={14} className="text-violet-500" />
              <span className="text-[11px] font-semibold text-violet-600">Agregar accion</span>
            </button>
          </div>
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-slate-100 flex items-center justify-end gap-2">
          <button
            onClick={onCerrar}
            className="px-4 py-2 text-[11px] font-semibold text-slate-600 hover:bg-slate-100 rounded-xl transition-colors"
          >
            Cancelar
          </button>
          <button
            onClick={handleSubmit}
            className="px-5 py-2 bg-violet-500 text-white text-[11px] font-semibold rounded-xl hover:bg-violet-600 transition-colors shadow-md shadow-violet-500/20"
          >
            {flujo ? "Actualizar" : "Crear"} Flujo
          </button>
        </div>
      </div>

      {/* Selector de Accion */}
      {mostrarSelectorAccion && (
        <SelectorAccion
          onSeleccionar={agregarAccion}
          onCerrar={() => setMostrarSelectorAccion(false)}
        />
      )}
    </>
  );
}

"use client";

import { useFlujoHistorial } from "@/modulos/automatizacion/hooks";

interface FlujoHistorialProps {
  flujoId: string;
}

export function FlujoHistorial({ flujoId }: FlujoHistorialProps) {
  const { historial, stats, cargando, pagina, setPagina, total } = useFlujoHistorial(flujoId);

  if (cargando) {
    return <div className="text-center py-8 text-[11px] text-slate-400">Cargando historial...</div>;
  }

  return (
    <div className="space-y-4">
      {/* Stats */}
      {stats && (
        <div className="grid grid-cols-4 gap-3">
          <div className="bg-slate-50 rounded-lg p-3 text-center">
            <div className="text-lg font-bold text-slate-700">{stats.total}</div>
            <div className="text-[10px] text-slate-400">Total</div>
          </div>
          <div className="bg-emerald-50 rounded-lg p-3 text-center">
            <div className="text-lg font-bold text-emerald-700">{stats.exitosas}</div>
            <div className="text-[10px] text-emerald-500">Exitosas</div>
          </div>
          <div className="bg-red-50 rounded-lg p-3 text-center">
            <div className="text-lg font-bold text-red-700">{stats.fallidas}</div>
            <div className="text-[10px] text-red-500">Fallidas</div>
          </div>
          <div className="bg-violet-50 rounded-lg p-3 text-center">
            <div className="text-lg font-bold text-violet-700">{stats.tasaExito}%</div>
            <div className="text-[10px] text-violet-500">Exito</div>
          </div>
        </div>
      )}

      {/* Lista */}
      {historial.length === 0 ? (
        <div className="text-center py-8">
          <p className="text-[11px] text-slate-400">No hay ejecuciones registradas</p>
        </div>
      ) : (
        <div className="space-y-2">
          {historial.map((ejec: any) => (
            <div key={ejec.id} className="p-3 bg-slate-50 rounded-xl">
              <div className="flex items-center justify-between mb-1">
                <div className="flex items-center gap-2">
                  <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${
                    ejec.estado === "EXITOSO" ? "bg-emerald-100 text-emerald-700" :
                    ejec.estado === "FALLIDO" ? "bg-red-100 text-red-700" :
                    "bg-amber-100 text-amber-700"
                  }`}>
                    {ejec.estado}
                  </span>
                  <span className="text-[11px] font-semibold text-slate-700">{ejec.leadNombre || "Sin lead"}</span>
                </div>
                <span className="text-[10px] text-slate-400">
                  {new Date(ejec.ejecutadoEn || ejec.ejecutado_en).toLocaleString("es-CL")}
                </span>
              </div>
              {ejec.accionesEjecutadas && (
                <div className="flex flex-wrap gap-1 mt-1">
                  {JSON.parse(typeof ejec.accionesEjecutadas === "string" ? ejec.accionesEjecutadas : "[]").map((a: any, idx: number) => (
                    <span key={idx} className={`text-[9px] px-1.5 py-0.5 rounded ${
                      a.estado === "EXITOSO" ? "bg-emerald-50 text-emerald-600" : "bg-red-50 text-red-600"
                    }`}>
                      {a.tipo}: {a.estado}
                    </span>
                  ))}
                </div>
              )}
              {ejec.errorMensaje && (
                <p className="text-[10px] text-red-500 mt-1">{ejec.errorMensaje}</p>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Paginacion */}
      {total > 20 && (
        <div className="flex items-center justify-center gap-2 pt-2">
          <button
            onClick={() => setPagina((p) => Math.max(1, p - 1))}
            disabled={pagina === 1}
            className="px-3 py-1 text-[10px] font-semibold bg-slate-100 rounded-lg disabled:opacity-50"
          >
            Anterior
          </button>
          <span className="text-[10px] text-slate-400">Pagina {pagina}</span>
          <button
            onClick={() => setPagina((p) => p + 1)}
            disabled={historial.length < 20}
            className="px-3 py-1 text-[10px] font-semibold bg-slate-100 rounded-lg disabled:opacity-50"
          >
            Siguiente
          </button>
        </div>
      )}
    </div>
  );
}

"use client";

import { GripVertical, Trash2, Zap } from "lucide-react";
import { ACCIONES_TIPOS } from "@/modulos/automatizacion/config";

interface PasoFlujoProps {
  paso: any;
  index: number;
  onEliminar: (index: number) => void;
  onActualizar: (index: number, campo: string, valor: any) => void;
  isDragging?: boolean;
}

export function PasoFlujo({ paso, index, onEliminar, onActualizar, isDragging }: PasoFlujoProps) {
  const accionConfig = ACCIONES_TIPOS.find((a) => a.id === paso.tipo);

  return (
    <div
      className={`flex items-center gap-3 p-3 bg-slate-50 rounded-xl border transition-all ${
        isDragging ? "border-violet-300 shadow-md" : "border-slate-200/60"
      }`}
    >
      {/* Drag Handle */}
      <div className="cursor-grab active:cursor-grabbing text-slate-400 hover:text-slate-600">
        <GripVertical size={16} />
      </div>

      {/* Numero */}
      <span className="text-[11px] font-bold text-slate-400 w-5">{index + 1}</span>

      {/* Icono de accion */}
      <div
        className="w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0"
        style={{ backgroundColor: `${accionConfig?.color || "#64748B"}15` }}
      >
        <Zap size={14} style={{ color: accionConfig?.color || "#64748B" }} />
      </div>

      {/* Info */}
      <div className="flex-1 min-w-0">
        <span className="text-[11px] font-semibold text-slate-700 block">
          {accionConfig?.label || paso.tipo}
        </span>
        {paso.configuracion?.plantilla && (
          <span className="text-[10px] text-slate-400 block">
            Plantilla: {paso.configuracion.plantilla}
          </span>
        )}
      </div>

      {/* Delay */}
      <div className="flex items-center gap-1">
        <input
          type="number"
          placeholder="0"
          value={paso.delay || ""}
          onChange={(e) => onActualizar(index, "delay", parseInt(e.target.value) || 0)}
          className="w-16 h-7 px-2 bg-white border border-slate-200 rounded-lg text-[10px] text-slate-600 text-center"
        />
        <span className="text-[9px] text-slate-400">min</span>
      </div>

      {/* Eliminar */}
      <button
        onClick={() => onEliminar(index)}
        className="p-1 text-red-400 hover:text-red-600 hover:bg-red-50 rounded transition-colors"
      >
        <Trash2 size={12} />
      </button>
    </div>
  );
}

"use client";

import { useState } from "react";
import {
  Globe,
  Copy,
  Check,
  ExternalLink,
  Code,
  AlertCircle,
  Settings,
  RefreshCw,
  TestTube,
  Send,
  Link2,
  FileText,
  AlertTriangle,
} from "lucide-react";
import { toast } from "sonner";

export function WordPressIntegration() {
  const [copiado, setCopiado] = useState<string | null>(null);
  const [testEmail, setTestEmail] = useState("");
  const [testNombre, setTestNombre] = useState("");
  const [testTelefono, setTestTelefono] = useState("");
  const [testEnviando, setTestEnviando] = useState(false);

  const webhookUrl = `${typeof window !== "undefined" ? window.location.origin : "http://localhost:3000"}/api/webhook/leads`;
  const apiUrl = `${typeof window !== "undefined" ? window.location.origin : "http://localhost:3000"}/api/leads`;

  const copiarAlPortapapeles = (texto: string, id: string) => {
    navigator.clipboard.writeText(texto);
    setCopiado(id);
    toast.success("Copiado al portapapeles");
    setTimeout(() => setCopiado(null), 2000);
  };

  const enviarTest = async () => {
    if (!testNombre || !testEmail) {
      toast.error("Nombre y email son requeridos");
      return;
    }

    setTestEnviando(true);
    try {
      const response = await fetch(apiUrl, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          nombre: testNombre.split(" ")[0] || testNombre,
          apellido: testNombre.split(" ").slice(1).join(" ") || "Test",
          email: testEmail,
          telefono: testTelefono,
          origen: "WEB",
          mensaje: "Lead de prueba desde integración WordPress",
        }),
      });

      const data = await response.json();
      if (data.success) {
        toast.success("Lead de prueba enviado correctamente");
        setTestNombre("");
        setTestEmail("");
        setTestTelefono("");
      } else {
        toast.error("Error al enviar lead de prueba");
      }
    } catch (error) {
      toast.error("Error de conexión");
    } finally {
      setTestEnviando(false);
    }
  };

  const codigoElementor = `
// En Elementor > Formulario > Configuración > Webhooks:
// 1. Agrega un nuevo webhook
// 2. URL: ${webhookUrl}
// 3. Método: POST
