                    <span className="flex-1">{item.label}</span>
                    {item.badge && (
                      <span className={`${item.badgeColor || "bg-red-500"} text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full min-w-[20px] text-center`}>
