    dicomDetalle: "",
    rentaMensual: "",
    complementarRenta: false,
    tipoCredito: "",
    cuentaPie: false,
    comentarios: "",
    origen: "WEB",
    etapa: "NUEVO_LEAD",
    prioridad: "MEDIA",
    banco: "",
