              <User size={14} /> Completar mi perfil
            </button>
          </div>
          </>
          )}

          {/* Tab Documentos */}
          {tabActiva === "documentos" && (
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
