export function TableroKanban({
  tareas,
  onMoverTarea,
  onVerTarea,
  onEditarTarea,
}: TableroKanbanProps) {
  const tareasPorColumna = useMemo(() => {
    const map: Record<EstadoTarea, Tarea[]> = {
      PENDIENTE: [],
      EN_PROGRESO: [],
      COMPLETADA: [],
      VENCIDA: [],
    };
    tareas.forEach((t) => {
      if (map[t.estado]) map[t.estado].push(t);
    });
    return map;
  }, [tareas]);

  const onDragEnd = (result: DropResult) => {
    if (!result.destination) return;
    const { source, destination } = result;
    if (
      source.droppableId === destination.droppableId &&
      source.index === destination.index
    )
      return;

    const tareaId = result.draggableId;
    const nuevoEstado = destination.droppableId as EstadoTarea;
    onMoverTarea(tareaId, nuevoEstado);
  };

  return (
    <DragDropContext onDragEnd={onDragEnd}>
      <div className="flex gap-4 h-[calc(100vh-200px)] overflow-x-auto pb-4">
        {COLUMNAS.map(({ estado, icono, color }) => {
          const tareasColumna = tareasPorColumna[estado];
          const config = ESTADOS_TAREA_CONFIG[estado];

          return (
            <div
              key={estado}
              className="min-w-[300px] w-[300px] flex-shrink-0 flex flex-col"
            >
              {/* Column Header */}
              <div className="bg-white rounded-2xl border border-slate-100/80 p-4 mb-3 flex-shrink-0 shadow-sm">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2.5">
                    <div
                      className="w-8 h-8 rounded-xl flex items-center justify-center"
                      style={{ backgroundColor: `${color}15`, color }}
                    >
                      {icono}
                    </div>
                    <div>
                      <span className="text-[12px] font-bold text-slate-800 block">
                        {config.label}
                      </span>
                      <span className="text-[10px] text-slate-400">
                        {tareasColumna.length} tarea{tareasColumna.length !== 1 ? "s" : ""}
                      </span>
                    </div>
                  </div>
                  <div
                    className="w-8 h-8 rounded-xl flex items-center justify-center text-[11px] font-bold"
                    style={{
                      backgroundColor: `${color}10`,
                      color,
                    }}
                  >
                    {tareasColumna.length}
                  </div>
                </div>
              </div>

              {/* Droppable Area */}
              <Droppable droppableId={estado}>
                {(provided, snapshot) => (
                  <div
                    ref={provided.innerRef}
                    {...provided.droppableProps}
                    className={`flex-1 rounded-2xl p-2.5 overflow-y-auto transition-all duration-200 ${
                      snapshot.isDraggingOver
                        ? "bg-blue-50/80 border-2 border-dashed border-blue-300"
                        : "bg-slate-50/30 border-2 border-transparent"
                    }`}
                  >
                    {tareasColumna.length === 0 ? (
                      <div className="h-full flex flex-col items-center justify-center text-center p-4 min-h-[200px]">
                        <div
                          className="w-14 h-14 rounded-2xl flex items-center justify-center mb-3"
                          style={{ backgroundColor: `${color}10`, color }}
                        >
                          {icono}
                        </div>
                        <p className="text-[12px] text-slate-400 font-medium mb-1">
                          Sin tareas
                        </p>
                        <p className="text-[10px] text-slate-300">
                          Arrastra tareas aquí
                        </p>
                      </div>
                    ) : (
                      <div className="space-y-2.5">
                        {tareasColumna.map((tarea, index) => (
                          <Draggable
                            key={tarea.id}
                            draggableId={tarea.id}
                            index={index}
                          >
                            {(provided, snapshot) => (
                              <div
                                ref={provided.innerRef}
                                {...provided.draggableProps}
                                {...provided.dragHandleProps}
                                className={`group bg-white rounded-xl border transition-all duration-200 ${
                                  snapshot.isDragging
                                    ? "shadow-2xl ring-2 ring-blue-500/30 scale-[1.02] rotate-[1deg] z-50"
                                    : "border-slate-100 hover:shadow-lg hover:border-slate-200 hover:-translate-y-0.5"
                                }`}
                              >
                                {/* Priority indicator */}
                                <div
                                  className="h-1 rounded-t-xl"
                                  style={{
                                    backgroundColor: prioridadStyles[tarea.prioridad].dot,
                                  }}
                                />

                                <div className="p-3.5">
                                  {/* Header */}
                                  <div className="flex items-start justify-between mb-2.5">
                                    <div className="flex-1 min-w-0">
                                      <h4 className="text-[12px] font-bold text-slate-800 leading-tight mb-1">
                                        {tarea.titulo}
                                      </h4>
                                      {tarea.descripcion && (
                                        <p className="text-[10px] text-slate-400 line-clamp-2 leading-relaxed">
                                          {tarea.descripcion}
                                        </p>
                                      )}
                                    </div>
                                  </div>

                                  {/* Badges */}
                                  <div className="flex items-center gap-1.5 mb-3">
                                    <span
                                      className={`text-[9px] font-bold px-2 py-0.5 rounded-md ${prioridadStyles[tarea.prioridad].bg} ${prioridadStyles[tarea.prioridad].text}`}
                                    >
                                      {tarea.prioridad}
                                    </span>
                                    <span
                                      className="text-[9px] font-semibold px-2 py-0.5 rounded-md"
                                      style={{
                                        backgroundColor: `${TIPOS_TAREA_CONFIG[tarea.tipo].color}12`,
                                        color: TIPOS_TAREA_CONFIG[tarea.tipo].color,
                                      }}
                                    >
                                      {TIPOS_TAREA_CONFIG[tarea.tipo].label}
                                    </span>
                                  </div>

                                  {/* Lead info */}
                                  {tarea.leadNombre && (
                                    <div className="flex items-center gap-2 mb-2.5 p-2 bg-slate-50/80 rounded-lg">
                                      <div className="w-6 h-6 bg-gradient-to-br from-blue-400 to-blue-500 rounded-md flex items-center justify-center text-[8px] font-bold text-white">
                                        {tarea.leadNombre.split(" ").map((n) => n[0]).join("")}
                                      </div>
                                      <span className="text-[10px] text-slate-600 font-medium truncate">
                                        {tarea.leadNombre}
                                      </span>
                                    </div>
                                  )}

                                  {/* Meta info */}
                                  <div className="flex items-center gap-3 mb-3">
                                    {tarea.fechaVencimiento && (
                                      <div className="flex items-center gap-1">
                                        <Calendar size={10} className="text-slate-400" />
                                        <span
                                          className={`text-[10px] ${
                                            new Date(tarea.fechaVencimiento) < new Date() &&
                                            tarea.estado !== "COMPLETADA"
                                              ? "text-red-500 font-semibold"
                                              : "text-slate-500"
                                          }`}
                                        >
                                          {new Date(tarea.fechaVencimiento).toLocaleDateString("es-CL", {
                                            day: "numeric",
                                            month: "short",
                                          })}
                                        </span>
                                      </div>
                                    )}
                                    {tarea.duracionEstimada && (
                                      <div className="flex items-center gap-1">
                                        <Timer size={10} className="text-slate-400" />
                                        <span className="text-[10px] text-slate-500">
                                          {tarea.duracionEstimada}min
                                        </span>
                                      </div>
                                    )}
                                    {tarea.comentarios.length > 0 && (
                                      <div className="flex items-center gap-1">
                                        <MessageSquare size={10} className="text-slate-400" />
                                        <span className="text-[10px] text-slate-500">
                                          {tarea.comentarios.length}
                                        </span>
                                      </div>
                                    )}
                                  </div>

                                  {/* Footer */}
                                  <div className="flex items-center justify-between pt-2.5 border-t border-slate-100">
                                    <div className="flex items-center gap-2">
                                      <div className="w-6 h-6 bg-gradient-to-br from-slate-400 to-slate-500 rounded-lg flex items-center justify-center text-[8px] font-bold text-white">
                                        {tarea.nombreEjecutivo
                                          ?.split(" ")
                                          .map((n) => n[0])
                                          .join("")}
                                      </div>
                                      <span className="text-[10px] text-slate-600 font-medium">
                                        {tarea.nombreEjecutivo?.split(" ")[0] || "Sin asignar"}
                                      </span>
                                    </div>
                                    <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                      <button
                                        onClick={(e) => {
                                          e.stopPropagation();
                                          onVerTarea(tarea);
                                        }}
                                        className="p-1.5 hover:bg-blue-50 rounded-lg transition-colors"
                                        title="Ver detalle"
                                      >
                                        <Eye size={12} className="text-blue-500" />
                                      </button>
                                      <button
                                        onClick={(e) => {
                                          e.stopPropagation();
                                          onEditarTarea(tarea);
                                        }}
                                        className="p-1.5 hover:bg-amber-50 rounded-lg transition-colors"
                                        title="Editar"
                                      >
                                        <Pencil size={12} className="text-amber-500" />
                                      </button>
                                    </div>
                                  </div>
                                </div>
                              </div>
                            )}
                          </Draggable>
                        ))}
                      </div>
                    )}
                    {provided.placeholder}
                  </div>
                )}
              </Droppable>
            </div>
          );
        })}
      </div>
    </DragDropContext>
  );
}

"use client";

import { useState, useMemo, useEffect, useRef } from "react";
import {
  ChevronLeft,
  ChevronRight,
  Clock,
  Eye,
  Pencil,
  Calendar,
  User,
  Timer,
  LayoutGrid,
  Rows3,
  Sun,
  AlertCircle,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { ESTADOS_TAREA_CONFIG, TIPOS_TAREA_CONFIG } from "@/tipos";
import type { Tarea, EstadoTarea, TipoTarea } from "@/tipos";

interface VistaCalendarioProps {
  tareas: Tarea[];
  onVerTarea: (tarea: Tarea) => void;
  onEditarTarea: (tarea: Tarea) => void;
}

type VistaCalendario = "mes" | "semana" | "dia";

const DIAS_SEMANA_COMPLETOS = [
  "Lunes",
  "Martes",
  "Miércoles",
  "Jueves",
  "Viernes",
  "Sábado",
  "Domingo",
];
const DIAS_SEMANA_CORTOS = ["Lun", "Mar", "Mié", "Jue", "Vie", "Sáb", "Dom"];
const MESES = [
  "Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio",
  "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre",
];

const estadoColores: Record<EstadoTarea, string> = {
  PENDIENTE: "#F59E0B",
  EN_PROGRESO: "#3B82F6",
  COMPLETADA: "#10B981",
  VENCIDA: "#EF4444",
};

const horasDelDia = Array.from({ length: 14 }, (_, i) => i + 7); // 7:00 a 20:00

export function VistaCalendario({
  tareas,
  onVerTarea,
  onEditarTarea,
}: VistaCalendarioProps) {
  const hoy = new Date();
  const [vistaActiva, setVistaActiva] = useState<VistaCalendario>("mes");
  const [fechaActual, setFechaActual] = useState(new Date());
  const [diaSeleccionado, setDiaSeleccionado] = useState<Date | null>(null);
  const [horaActual, setHoraActual] = useState(new Date());
  const timeRef = useRef<NodeJS.Timeout | null>(null);

  // Actualizar hora actual cada minuto
  useEffect(() => {
    timeRef.current = setInterval(() => setHoraActual(new Date()), 60000);
    return () => {
      if (timeRef.current) clearInterval(timeRef.current);
    };
  }, []);

  // Obtener inicio de la semana (lunes)
  const inicioSemana = useMemo(() => {
    const d = new Date(fechaActual);
    const dia = d.getDay();
    const diff = d.getDate() - dia + (dia === 0 ? -6 : 1);
    d.setDate(diff);
    d.setHours(0, 0, 0, 0);
    return d;
  }, [fechaActual]);

  // Días de la semana actual
  const diasSemana = useMemo(() => {
    const dias: Date[] = [];
    for (let i = 0; i < 7; i++) {
      const d = new Date(inicioSemana);
      d.setDate(d.getDate() + i);
      dias.push(d);
    }
    return dias;
  }, [inicioSemana]);

  // Tareas agrupadas por día
  const tareasPorDia = useMemo(() => {
    const map: Record<string, Tarea[]> = {};
    tareas.forEach((t) => {
      if (!t.fechaVencimiento) return;
      const fv = new Date(t.fechaVencimiento);
      const key = `${fv.getFullYear()}-${fv.getMonth()}-${fv.getDate()}`;
      if (!map[key]) map[key] = [];
      map[key].push(t);
    });
    return map;
  }, [tareas]);

  const getTareasDelDia = (fecha: Date) => {
    const key = `${fecha.getFullYear()}-${fecha.getMonth()}-${fecha.getDate()}`;
    return tareasPorDia[key] || [];
  };

  // Navegación
  const irAAnterior = () => {
    const nueva = new Date(fechaActual);
    if (vistaActiva === "mes") nueva.setMonth(nueva.getMonth() - 1);
    else if (vistaActiva === "semana") nueva.setDate(nueva.getDate() - 7);
    else nueva.setDate(nueva.getDate() - 1);
    setFechaActual(nueva);
  };

  const irASiguiente = () => {
    const nueva = new Date(fechaActual);
    if (vistaActiva === "mes") nueva.setMonth(nueva.getMonth() + 1);
    else if (vistaActiva === "semana") nueva.setDate(nueva.getDate() + 7);
    else nueva.setDate(nueva.getDate() + 1);
    setFechaActual(nueva);
  };

  const irAHoy = () => {
    setFechaActual(new Date());
    setDiaSeleccionado(new Date());
    if (vistaActiva === "dia") {
      // keep dia view
    }
  };

  const esHoy = (fecha: Date) =>
    fecha.getDate() === hoy.getDate() &&
    fecha.getMonth() === hoy.getMonth() &&
    fecha.getFullYear() === hoy.getFullYear();

  const esMismaFecha = (a: Date, b: Date) =>
    a.getDate() === b.getDate() &&
    a.getMonth() === b.getMonth() &&
    a.getFullYear() === b.getFullYear();

  const tituloVista = () => {
    if (vistaActiva === "mes") {
      return `${MESES[fechaActual.getMonth()]} ${fechaActual.getFullYear()}`;
    }
    if (vistaActiva === "semana") {
      const fin = new Date(inicioSemana);
      fin.setDate(fin.getDate() + 6);
      if (inicioSemana.getMonth() === fin.getMonth()) {
        return `${inicioSemana.getDate()} - ${fin.getDate()} ${MESES[inicioSemana.getMonth()]} ${inicioSemana.getFullYear()}`;
      }
      return `${inicioSemana.getDate()} ${MESES[inicioSemana.getMonth()].slice(0, 3)} - ${fin.getDate()} ${MESES[fin.getMonth()].slice(0, 3)} ${fin.getFullYear()}`;
    }
    return `${DIAS_SEMANA_COMPLETOS[fechaActual.getDay() === 0 ? 6 : fechaActual.getDay() - 1]} ${fechaActual.getDate()} de ${MESES[fechaActual.getMonth()]} ${fechaActual.getFullYear()}`;
  };

  // Posición de la línea de hora actual
  const getPosicionHora = () => {
    const hora = horaActual.getHours();
    const minuto = horaActual.getMinutes();
    return ((hora - 7) * 60 + minuto) * (56 / 60); // 56px por hora
  };

  return (
    <div className="flex gap-4 h-[calc(100vh-200px)]">
      {/* Panel izquierdo - Calendario principal */}
      <div className="flex-1 bg-white rounded-2xl border border-slate-100/80 shadow-soft overflow-hidden flex flex-col">
        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-slate-100">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <button
                onClick={irAAnterior}
                className="w-9 h-9 flex items-center justify-center hover:bg-slate-100 rounded-xl transition-colors"
              >
                <ChevronLeft size={18} className="text-slate-600" />
              </button>
              <h2 className="text-base font-bold text-slate-900 min-w-[200px] text-center">
                {tituloVista()}
              </h2>
              <button
                onClick={irASiguiente}
                className="w-9 h-9 flex items-center justify-center hover:bg-slate-100 rounded-xl transition-colors"
              >
                <ChevronRight size={18} className="text-slate-600" />
              </button>
            </div>
            <Button variant="outline" size="sm" onClick={irAHoy}>
              Hoy
            </Button>
          </div>

          <div className="flex items-center gap-3">
            {/* Leyenda */}
            <div className="hidden lg:flex items-center gap-3 mr-4">
              {Object.entries(estadoColores).map(([estado, color]) => (
                <div key={estado} className="flex items-center gap-1.5 text-[10px] text-slate-500">
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: color }} />
                  <span>{ESTADOS_TAREA_CONFIG[estado as EstadoTarea].label}</span>
                </div>
              ))}
            </div>

            {/* Selector de vista */}
            <div className="flex bg-slate-100 rounded-lg p-0.5">
              <button
                onClick={() => setVistaActiva("mes")}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-[10px] font-semibold transition-all ${
                  vistaActiva === "mes"
                    ? "bg-white text-blue-600 shadow-sm"
                    : "text-slate-500 hover:text-slate-700"
                }`}
              >
                <LayoutGrid size={12} /> Mes
              </button>
              <button
                onClick={() => setVistaActiva("semana")}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-[10px] font-semibold transition-all ${
                  vistaActiva === "semana"
                    ? "bg-white text-blue-600 shadow-sm"
                    : "text-slate-500 hover:text-slate-700"
                }`}
              >
                <Rows3 size={12} /> Semana
              </button>
              <button
                onClick={() => setVistaActiva("dia")}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-[10px] font-semibold transition-all ${
                  vistaActiva === "dia"
                    ? "bg-white text-blue-600 shadow-sm"
                    : "text-slate-500 hover:text-slate-700"
                }`}
              >
                <Sun size={12} /> Día
              </button>
            </div>
          </div>
        </div>

        {/* Vista Mes */}
        {vistaActiva === "mes" && (
          <VistaMes
            fechaActual={fechaActual}
            tareasPorDia={tareasPorDia}
            getTareasDelDia={getTareasDelDia}
            esHoy={esHoy}
            onDiaClick={(fecha) => {
              setDiaSeleccionado(fecha);
              setFechaActual(fecha);
              setVistaActiva("dia");
            }}
            onVerTarea={onVerTarea}
            onEditarTarea={onEditarTarea}
          />
        )}

        {/* Vista Semana */}
        {vistaActiva === "semana" && (
          <VistaSemana
            diasSemana={diasSemana}
            getTareasDelDia={getTareasDelDia}
            esHoy={esHoy}
            esMismaFecha={esMismaFecha}
            fechaActual={fechaActual}
            horaActual={horaActual}
           getPosicionHora={getPosicionHora}
            onDiaClick={(fecha) => {
              setDiaSeleccionado(fecha);
              setFechaActual(fecha);
              setVistaActiva("dia");
            }}
            onVerTarea={onVerTarea}
            onEditarTarea={onEditarTarea}
          />
        )}

        {/* Vista Día */}
        {vistaActiva === "dia" && (
          <VistaDia
            fecha={diaSeleccionado || fechaActual}
            getTareasDelDia={getTareasDelDia}
            esHoy={esHoy}
            horaActual={horaActual}
           getPosicionHora={getPosicionHora}
            onVerTarea={onVerTarea}
            onEditarTarea={onEditarTarea}
          />
        )}
      </div>

      {/* Panel lateral derecho */}
      <div className="w-72 flex-shrink-0 space-y-4">
        {/* Mini calendario */}
        <MiniCalendario
          fechaActual={fechaActual}
          onFechaClick={(fecha) => {
            setFechaActual(fecha);
            setDiaSeleccionado(fecha);
            setVistaActiva("dia");
          }}
        />

        {/* Tareas del día seleccionado */}
        <PanelDiaSeleccionado
          fecha={diaSeleccionado || new Date()}
          tareas={getTareasDelDia(diaSeleccionado || new Date())}
          onVerTarea={onVerTarea}
          onEditarTarea={onEditarTarea}
        />
      </div>
    </div>
  );
}

// ==================== VISTA MES ====================
function VistaMes({
  fechaActual,
  tareasPorDia,
  getTareasDelDia,
  esHoy,
  onDiaClick,
  onVerTarea,
  onEditarTarea,
}: {
  fechaActual: Date;
  tareasPorDia: Record<string, Tarea[]>;
  getTareasDelDia: (fecha: Date) => Tarea[];
  esHoy: (fecha: Date) => boolean;
  onDiaClick: (fecha: Date) => void;
  onVerTarea: (tarea: Tarea) => void;
  onEditarTarea: (tarea: Tarea) => void;
}) {
  const diasDelMes = useMemo(() => {
    const primerDia = new Date(fechaActual.getFullYear(), fechaActual.getMonth(), 1);
    const ultimoDia = new Date(fechaActual.getFullYear(), fechaActual.getMonth() + 1, 0);
    const diasEnMes = ultimoDia.getDate();

    let diaSemana = primerDia.getDay() - 1;
    if (diaSemana < 0) diaSemana = 6;

    const dias: (Date | null)[] = [];
    for (let i = 0; i < diaSemana; i++) dias.push(null);
    for (let i = 1; i <= diasEnMes; i++) {
      dias.push(new Date(fechaActual.getFullYear(), fechaActual.getMonth(), i));
    }
    return dias;
  }, [fechaActual]);

  return (
    <div className="flex flex-col flex-1">
      {/* Header días */}
      <div className="grid grid-cols-7 border-b border-slate-100 bg-slate-50/50">
        {DIAS_SEMANA_CORTOS.map((dia) => (
          <div key={dia} className="p-3 text-center text-[10px] font-bold text-slate-400 uppercase tracking-wider">
            {dia}
          </div>
        ))}
      </div>

      {/* Grid */}
      <div className="grid grid-cols-7 flex-1">
        {diasDelMes.map((dia, idx) => {
          if (!dia) {
            return <div key={`empty-${idx}`} className="min-h-[100px] bg-slate-50/30 border-b border-r border-slate-100" />;
          }

          const tareasDelDia = getTareasDelDia(dia);
          const hoy = esHoy(dia);
          const esFinDeSemana = idx % 7 >= 5;

          return (
            <div
              key={dia.getTime()}
              onClick={() => onDiaClick(dia)}
              className={`min-h-[100px] p-2 border-b border-r border-slate-100 cursor-pointer transition-all duration-150 hover:bg-blue-50/30 ${
                esFinDeSemana ? "bg-slate-50/50" : ""
              }`}
            >
              <div className="flex items-center justify-between mb-1.5">
                <span
