/**
 * Hooks del módulo Clientes
 */

import { useState, useEffect } from "react";
import { obtenerClientePorId, obtenerDocumentosCliente } from "./servicios";

/**
 * Hook para cargar datos del cliente
 * @param leadId - ID del lead/cliente
 */
export function useCliente(leadId: string | null) {
  const [cliente, setCliente] = useState<any>(null);
  const [cargando, setCargando] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!leadId) {
      setCargando(false);
      return;
    }

    async function cargarCliente() {
      try {
        setCargando(true);
        const result = await obtenerClientePorId(leadId as string);
        if (result.success) {
          setCliente(result.data);
        }
      } catch (err) {
        setError(err instanceof Error ? err.message : "Error al cargar cliente");
      } finally {
        setCargando(false);
      }
    }

    cargarCliente();
  }, [leadId]);

  return { cliente, cargando, error, setCliente };
}

/**
 * Hook para documentos del cliente
 * @param leadId - ID del lead/cliente
 */
export function useDocumentosCliente(leadId: string | null) {
  const [documentos, setDocumentos] = useState<any[]>([]);
  const [cargando, setCargando] = useState(true);

  useEffect(() => {
    if (!leadId) {
      setCargando(false);
      return;
    }

    async function cargarDocumentos() {
      try {
        setCargando(true);
        const result = await obtenerDocumentosCliente(leadId as string);
        if (result.success) {
          setDocumentos(result.data);
        }
      } catch (err) {
        console.error("Error cargando documentos:", err);
      } finally {
        setCargando(false);
      }
    }

    cargarDocumentos();
  }, [leadId]);

  const documentosAprobados = documentos.filter(
    (d) => d.estado === "APROBADO" || d.estado === "RECIBIDO"
  ).length;

  const documentosPendientes = documentos.length - documentosAprobados;

  return {
    documentos,
    setDocumentos,
    cargando,
    documentosAprobados,
    documentosPendientes,
    totalDocumentos: documentos.length,
  };
}

/**
 * Servicios del módulo Clientes
 * Funciones para CRUD de clientes, perfil, documentos
 */

import type { PerfilClienteInput } from "./validaciones";

const API_BASE = "/api/leads";

// ─── Helpers ───
async function apiRequest<T>(url: string, options?: RequestInit): Promise<T> {
  const response = await fetch(url, {
    credentials: "include",
    headers: { "Content-Type": "application/json" },
    ...options,
  });

  if (!response.ok) {
    const error = await response.json().catch(() => ({ error: "Error desconocido" }));
    throw new Error(error.error || `Error HTTP ${response.status}`);
  }

  return response.json();
}

// ─── Obtener cliente por ID ───
export async function obtenerClientePorId(id: string) {
  return apiRequest<{ success: boolean; data: any }>(`${API_BASE}/${id}`);
}

// ─── Actualizar perfil del cliente ───
export async function actualizarPerfilCliente(id: string, data: PerfilClienteInput) {
  return apiRequest<{ success: boolean; data: any }>(`${API_BASE}/${id}`, {
    method: "PUT",
    body: JSON.stringify(data),
  });
}

// ─── Obtener documentos del cliente ───
export async function obtenerDocumentosCliente(leadId: string) {
  return apiRequest<{ success: boolean; data: any[] }>(
    `/api/documentos?leadId=${leadId}`
  );
}

// ─── Subir documento ───
export async function subirDocumento(leadId: string, archivo: File, nombre: string) {
  const formData = new FormData();
  formData.append("archivo", archivo);
  formData.append("leadId", leadId);
  formData.append("nombre", nombre);

  const response = await fetch("/api/upload", {
    method: "POST",
    credentials: "include",
    body: formData,
  });

