  | "solicitud:stage:changed";

export type TipoAccion =
  | "asignar_ejecutivo"
  | "enviar_email"
  | "crear_tarea"
  | "mover_pipeline"
  | "enviar_whatsapp"
  | "crear_recordatorio"
  | "notificar_ejecutivo"
  | "actualizar_estado";

export interface Workflow {
  id: string;
  nombre: string;
  descripcion?: string;
  estado: "BORRADOR" | "ACTIVO" | "PAUSADO";
  trigger: TipoTrigger;
  condiciones?: Condicion[];
  acciones: Accion[];
  ejecuciones: number;
  ultimoEjecucion?: string;
  creadoEn: string;
}

export interface Condicion {
  campo: string;
  operador: "igual" | "contiene" | "mayor" | "menor" | "existe";
  valor: string;
}

export interface Accion {
  tipo: TipoAccion;
  configuracion: Record<string, any>;
  orden: number;
}

